export type Role = 'student' | 'admin';
export type Gender = 'male' | 'female';
export type FileType = 'slides' | 'past_questions' | 'notes' | 'other' | 'books';
export type BookingStatus = 'pending' | 'confirmed' | 'cancelled';
export type TargetType = 'all' | 'program' | 'course';

export interface User {
  id: string;
  name: string;
  email: string;
  role: Role;
  gender: Gender;
  studentId?: string;
  program?: string;
  profileImage?: string;
}

export interface Announcement {
  id: string;
  title: string;
  message: string;
  category: 'URGENT' | 'ACADEMIC' | 'GENERAL' | 'EVENT';
  created_at: string;
  target_type: TargetType;
  is_active: boolean;
}

export interface ClassSchedule {
  id: string;
  course_id: string;
  course_name: string;
  instructor_name: string;
  day_of_week: string;
  start_time: string;
  end_time: string;
  location: string;
  semester: string;
}

export interface Hostel {
  id: string;
  name: string;
  total_floors: number;
  description: string;
  image: string;
}

export interface Room {
  id: string;
  hostel_id: string;
  floor_id: string;
  room_number: number;
  type: '2-in-a-room' | '4-in-a-room';
  status: 'available' | 'booked';
  price: number;
}

export interface Club {
  id: string;
  name: string;
  description: string;
  category: string;
  members: number;
  whatsapp_link: string;
  image: string;
}

export interface Poll {
  id: string;
  question: string;
  options: string[];
  votes: Record<string, number>;
  totalVotes: number;
  hasVoted: boolean;
  endDate: string;
}

export interface LibraryFile {
  id: string;
  name: string;
  type: FileType;
  course: string;
  size: string;
  date: string;
  downloads: number;
}

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, useNavigate, useLocation } from 'react-router-dom';
import { ICONS, COLORS } from './constants';
import HomeView from './views/Home';
import ScheduleView from './views/Schedule';
import ClubsView from './views/Clubs';
import LibraryView from './views/Library';
import ProfileView from './views/Profile';
import HostelBookingView from './views/HostelBooking';
import PollsView from './views/Polls';
import { currentUser } from './mockData';

const BottomNav = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const currentPath = location.pathname;

  const tabs = [
    { path: '/', label: 'Home', Icon: ICONS.Home },
    { path: '/schedule', label: 'Schedule', Icon: ICONS.Schedule },
    { path: '/clubs', label: 'Clubs', Icon: ICONS.Clubs },
    { path: '/library', label: 'Library', Icon: ICONS.Library },
    { path: '/profile', label: 'Profile', Icon: ICONS.Profile },
  ];

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 px-6 py-3 flex justify-between items-center z-50 shadow-[0_-2px_10px_rgba(0,0,0,0.02)]">
      {tabs.map((tab) => {
        const isActive = currentPath === tab.path || (tab.path !== '/' && currentPath.startsWith(tab.path));
        return (
          <button
            key={tab.path}
            onClick={() => {
              navigate(tab.path);
              if (window.navigator.vibrate) window.navigator.vibrate(5);
            }}
            className="flex flex-col items-center gap-1 transition-all duration-200"
          >
            <tab.Icon
              size={24}
              color={isActive ? COLORS.primary : COLORS.muted}
              strokeWidth={isActive ? 2.5 : 2}
            />
            <span
              className={`text-[10px] font-medium ${
                isActive ? 'text-[#0088CC]' : 'text-slate-400'
              }`}
            >
              {tab.label}
            </span>
          </button>
        );
      })}
    </div>
  );
};

const App: React.FC = () => {
  return (
    <Router>
      <div className="max-w-md mx-auto min-h-screen pb-24 relative shadow-xl bg-slate-50 overflow-hidden flex flex-col">
        <Routes>
          <Route path="/" element={<HomeView />} />
          <Route path="/schedule" element={<ScheduleView />} />
          <Route path="/clubs" element={<ClubsView />} />
          <Route path="/library" element={<LibraryView />} />
          <Route path="/profile" element={<ProfileView />} />
          <Route path="/profile/hostel" element={<HostelBookingView />} />
          <Route path="/profile/polls" element={<PollsView />} />
        </Routes>
        <BottomNav />
      </div>
    </Router>
  );
};

export default App;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { announcements, currentUser, schedules } from '../mockData';
import { ICONS, COLORS } from '../constants';

const HomeView: React.FC = () => {
  const navigate = useNavigate();
  const [isRefreshing, setIsRefreshing] = useState(false);

  const handleRefresh = () => {
    setIsRefreshing(true);
    setTimeout(() => setIsRefreshing(false), 1500);
  };

  const quickActions = [
    { label: 'Schedule', Icon: ICONS.Schedule, color: 'bg-blue-50', iconColor: '#0088CC', path: '/schedule' },
    { label: 'Hostel', Icon: ICONS.Building, color: 'bg-emerald-50', iconColor: '#10B981', path: '/profile/hostel' },
    { label: 'Vote', Icon: ICONS.CheckCircle2, color: 'bg-purple-50', iconColor: '#8B5CF6', path: '/profile/polls' },
    { label: 'Library', Icon: ICONS.Library, color: 'bg-orange-50', iconColor: '#F59E0B', path: '/library' },
  ];

  return (
    <div className="flex-1 flex flex-col p-6 overflow-y-auto no-scrollbar pull-to-refresh-container animate-fade-in" onTouchEnd={(e) => {
        if (window.scrollY === 0) handleRefresh();
    }}>
      {/* Header */}
      <div className="flex justify-between items-start mb-8">
        <div>
          <p className="text-slate-500 text-sm mb-1">Welcome back,</p>
          <h1 className="text-2xl font-bold text-slate-900">{currentUser.name.split(' ')[0]}</h1>
        </div>
        <button className="p-2 bg-white rounded-xl shadow-sm border border-slate-100 relative">
          <ICONS.Bell size={20} className="text-slate-600" />
          <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
        </button>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-4 gap-4 mb-8">
        {quickActions.map((action) => (
          <button
            key={action.label}
            onClick={() => navigate(action.path)}
            className="flex flex-col items-center gap-2 group"
          >
            <div className={`w-14 h-14 ${action.color} rounded-2xl flex items-center justify-center transition-transform group-active:scale-90`}>
              <action.Icon color={action.iconColor} size={24} />
            </div>
            <span className="text-xs font-medium text-slate-600">{action.label}</span>
          </button>
        ))}
      </div>

      {/* Today's Classes */}
      <div className="mb-8">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-lg font-bold text-slate-900">Today's Classes</h2>
          <button onClick={() => navigate('/schedule')} className="text-[#0088CC] text-sm font-semibold flex items-center gap-1">
            See all <ICONS.ChevronRight size={16} />
          </button>
        </div>
        <div className="flex gap-4 overflow-x-auto no-scrollbar pb-2">
          {schedules.map((cls) => (
            <div key={cls.id} className="min-w-[280px] bg-[#0088CC] rounded-3xl p-5 text-white relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16"></div>
              <p className="text-xs opacity-80 font-medium mb-1">{cls.start_time} - {cls.end_time}</p>
              <h3 className="text-lg font-bold mb-3">{cls.course_name}</h3>
              <div className="flex items-center gap-2 text-xs opacity-90">
                <div className="bg-white/20 px-2 py-1 rounded-lg">{cls.location}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Announcements */}
      <div>
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-lg font-bold text-slate-900">Announcements</h2>
          <span className="bg-blue-100 text-[#0088CC] px-2 py-1 rounded-full text-[10px] font-bold">5 NEW</span>
        </div>
        <div className="space-y-4">
          {announcements.map((ann) => (
            <div key={ann.id} className="bg-white rounded-3xl p-5 shadow-sm border border-slate-100 transition-transform active:scale-[0.98]">
              <div className="flex items-center justify-between mb-3">
                <div className="flex items-center gap-2">
                    <span className={`w-1.5 h-1.5 rounded-full ${
