import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { hostels, currentUser } from '../mockData';
import { ICONS, COLORS } from '../constants';
import { Gender, Hostel } from '../types';

const HostelBookingView: React.FC = () => {
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [selectedGender, setSelectedGender] = useState<Gender>(currentUser.gender);
  const [selectedHostel, setSelectedHostel] = useState<Hostel | null>(null);
  const [selectedFloor, setSelectedFloor] = useState<number | null>(null);
  const [selectedRoom, setSelectedRoom] = useState<number | null>(null);

  // Simple logic for floor generation
  const floors = useMemo(() => {
    if (!selectedHostel) return [];
    const arr = [];
    for (let i = 0; i < selectedHostel.total_floors; i++) {
      const floorGender = i === 0 || i % 2 === 0 ? 'male' : 'female';
      if (floorGender === selectedGender) {
        arr.push({
          number: i,
          rooms: `${i === 0 ? '1 - 50' : i * 100 + 1 + ' - ' + (i * 100 + 50)}`
        });
      }
    }
    return arr;
  }, [selectedHostel, selectedGender]);

  // Generate rooms for a floor
  const roomsOnFloor = useMemo(() => {
    if (selectedFloor === null) return [];
    const arr = [];
    const base = selectedFloor === 0 ? 0 : selectedFloor * 100;
    for (let i = 1; i <= 50; i++) {
        const roomNum = base + i;
        const type = (roomNum % 100 === 15 || roomNum % 100 === 44) ? '2-bed' : '4-bed';
        arr.push({ number: roomNum, type });
    }
    return arr;
  }, [selectedFloor]);

  const handleNext = () => {
    if (step < 5) setStep(step + 1);
  };

  const handleBack = () => {
    if (step === 1) navigate('/profile');
    else setStep(step - 1);
  };

  const currentPrice = useMemo(() => {
    if (!selectedRoom) return 0;
    const isTwoBed = (selectedRoom % 100 === 15 || selectedRoom % 100 === 44);
    return isTwoBed ? 3500 : 2500;
  }, [selectedRoom]);

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <div className="flex flex-col gap-6">
            <h2 className="text-xl font-bold text-slate-900">Select Your Gender</h2>
            <div className="space-y-4">
              {(['male', 'female'] as Gender[]).map((g) => (
                <button
                  key={g}
                  onClick={() => setSelectedGender(g)}
                  className={`w-full p-6 rounded-3xl border-2 flex items-center justify-between transition-all ${
                    selectedGender === g ? 'border-[#0088CC] bg-blue-50/50' : 'border-slate-100 bg-white'
                  }`}
                >
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${g === 'male' ? 'bg-blue-100 text-[#0088CC]' : 'bg-pink-100 text-pink-500'}`}>
                      <ICONS.User size={24} />
                    </div>
                    <div className="text-left">
                      <p className="font-bold text-slate-900 capitalize">{g}</p>
                      <p className="text-xs text-slate-400">Access to {g} floors only</p>
                    </div>
                  </div>
                  {selectedGender === g && <div className="w-6 h-6 bg-[#0088CC] rounded-full flex items-center justify-center text-white"><ICONS.CheckCircle2 size={16} /></div>}
                </button>
              ))}
            </div>
          </div>
        );
      case 2:
        return (
          <div className="flex flex-col gap-6">
            <h2 className="text-xl font-bold text-slate-900">Choose Your Hostel</h2>
            <div className="space-y-4">
              {hostels.map((h) => (
                <button
                  key={h.id}
                  onClick={() => setSelectedHostel(h)}
                  className={`w-full p-5 rounded-3xl border-2 flex flex-col gap-4 transition-all ${
                    selectedHostel?.id === h.id ? 'border-[#0088CC] bg-blue-50/50' : 'border-slate-100 bg-white'
                  }`}
                >
                  <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-emerald-50 text-emerald-500 rounded-2xl flex items-center justify-center">
                      <ICONS.Building size={28} />
                    </div>
                    <div className="text-left flex-1">
                      <h3 className="font-bold text-slate-900">{h.name}</h3>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{h.total_floors} floors • {h.description}</p>
                    </div>
                  </div>
                </button>
              ))}
            </div>
          </div>
        );
      case 3:
        return (
          <div className="flex flex-col gap-6">
            <h2 className="text-xl font-bold text-slate-900">Select Floor</h2>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest -mt-4">Showing {selectedGender} floors only</p>
            <div className="space-y-4">
              {floors.map((f) => (
                <button
                  key={f.number}
                  onClick={() => setSelectedFloor(f.number)}
                  className={`w-full p-5 rounded-3xl border-2 flex items-center justify-between transition-all ${
                    selectedFloor === f.number ? 'border-[#0088CC] bg-blue-50/50 shadow-lg shadow-blue-50' : 'border-slate-100 bg-white shadow-sm'
                  }`}
                >
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-indigo-50 text-indigo-500 rounded-2xl flex items-center justify-center">
                      <ICONS.Info size={24} />
                    </div>
                    <div className="text-left">
                      <p className="font-bold text-slate-900">Floor {f.number}</p>
                      <p className="text-xs text-slate-400">Rooms {f.rooms}</p>
                    </div>
                  </div>
                  {selectedFloor === f.number && <div className="w-6 h-6 bg-[#0088CC] rounded-full flex items-center justify-center text-white"><ICONS.CheckCircle2 size={16} /></div>}
                </button>
              ))}
            </div>
          </div>
        );
      case 4:
        return (
          <div className="flex flex-col gap-6">
            <h2 className="text-xl font-bold text-slate-900">Select Room Number</h2>
            <div className="flex gap-4 mb-2">
                <div className="flex items-center gap-2"><div className="w-3 h-3 bg-amber-100 border border-amber-400 rounded"></div><span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">2-in-a-room</span></div>
                <div className="flex items-center gap-2"><div className="w-3 h-3 bg-white border border-slate-200 rounded"></div><span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">4-in-a-room</span></div>
            </div>
            <div className="grid grid-cols-4 gap-3">
              {roomsOnFloor.map((r) => (
                <button
                  key={r.number}
                  onClick={() => setSelectedRoom(r.number)}
                  className={`py-3 rounded-2xl border flex flex-col items-center justify-center transition-all ${
                    selectedRoom === r.number 
                        ? 'bg-[#0088CC] border-[#0088CC] text-white shadow-lg shadow-blue-200 scale-105 z-10' 
                        : r.type === '2-bed' 
                            ? 'bg-amber-50 border-amber-200' 
                            : 'bg-white border-slate-100 text-slate-900'
                  }`}
                >
                  <span className="text-sm font-bold">{r.number}</span>
                  <span className={`text-[8px] font-bold uppercase tracking-widest ${selectedRoom === r.number ? 'text-white/80' : 'text-slate-400'}`}>{r.type}</span>
                </button>
              ))}
            </div>
          </div>
        );
      case 5:
        return (
          <div className="flex flex-col gap-8">
            <h2 className="text-xl font-bold text-slate-900">Confirm Your Booking</h2>
            <div className="bg-white rounded-3xl overflow-hidden shadow-sm border border-slate-100">
                <div className="divide-y divide-slate-50">
                    <div className="flex justify-between p-6">
                        <span className="text-slate-400 font-medium">Hostel</span>
                        <span className="font-bold text-slate-900">{selectedHostel?.name}</span>
                    </div>
                    <div className="flex justify-between p-6">
                        <span className="text-slate-400 font-medium">Floor</span>
                        <span className="font-bold text-slate-900">Floor {selectedFloor}</span>
                    </div>
                    <div className="flex justify-between p-6">
                        <span className="text-slate-400 font-medium">Room</span>
                        <span className="font-bold text-slate-900">Room {selectedRoom}</span>
                    </div>
                    <div className="flex justify-between p-6">
                        <span className="text-slate-400 font-medium">Room Type</span>
                        <span className="font-bold text-slate-900">{(selectedRoom! % 100 === 15 || selectedRoom! % 100 === 44) ? '2-in-a-room' : '4-in-a-room'}</span>
                    </div>
                    <div className="flex justify-between p-6 bg-slate-50/50">
                        <span className="text-slate-400 font-medium">Price</span>
                        <span className="font-black text-2xl text-emerald-500">GHS {currentPrice.toLocaleString()}</span>
                    </div>
                </div>
            </div>
            <div className="bg-amber-50 p-5 rounded-3xl border border-amber-100 flex gap-4">
                <ICONS.Info className="text-amber-500 shrink-0" size={20} />
                <p className="text-xs text-amber-700 font-medium leading-relaxed">
                    Your booking will be pending until confirmed by an admin. Payment details will be provided upon confirmation.
                </p>
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  const isNextDisabled = () => {
    if (step === 2 && !selectedHostel) return true;
    if (step === 3 && selectedFloor === null) return true;
    if (step === 4 && selectedRoom === null) return true;
    return false;
  };

  return (
    <div className="flex-1 bg-slate-50 flex flex-col animate-fade-in relative h-full">
      {/* Top Header */}
      <div className="p-6 pb-2 bg-white flex items-center justify-between">
        <button onClick={handleBack} className="p-2 -ml-2 hover:bg-slate-50 rounded-full transition-colors">
          <ICONS.ChevronRight size={24} className="rotate-180 text-slate-600" />
        </button>
        <h1 className="font-bold text-slate-900">Hostel Booking</h1>
        <div className="w-10"></div>
      </div>

      {/* Stepper */}
      <div className="px-10 py-6 bg-white flex items-center justify-between">
        {[1, 2, 3, 4, 5].map((s) => (
          <React.Fragment key={s}>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold transition-all duration-300 ${
                step >= s ? 'bg-[#0088CC] text-white shadow-lg shadow-blue-100' : 'bg-slate-100 text-slate-400'
            }`}>
              {step > s ? <ICONS.CheckCircle2 size={16} /> : s}
            </div>
            {s < 5 && <div className={`flex-1 h-1 mx-2 rounded-full transition-all duration-300 ${step > s ? 'bg-[#0088CC]' : 'bg-slate-100'}`}></div>}
          </React.Fragment>
        ))}
      </div>

      {/* Content */}
      <div className="flex-1 p-6 overflow-y-auto no-scrollbar">
        {renderStep()}
      </div>

      {/* Footer Button */}
      <div className="p-6 bg-white border-t border-slate-100">
        <button
          disabled={isNextDisabled()}
          onClick={step === 5 ? () => navigate('/profile') : handleNext}
          className={`w-full py-4 rounded-2xl font-bold text-white transition-all active:scale-95 shadow-lg ${
            isNextDisabled() ? 'bg-slate-300 shadow-none' : 'bg-[#0088CC] shadow-blue-100'
          }`}
        >
          {step === 5 ? 'Submit Booking' : 'Continue'}
        </button>
      </div>
    </div>
  );
};

export default HostelBookingView;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { polls } from '../mockData';
import { ICONS, COLORS } from '../constants';

const PollsView: React.FC = () => {
  const navigate = useNavigate();
  const [activePolls, setActivePolls] = useState(polls);

  const handleVote = (pollId: string, option: string) => {
    setActivePolls(prev => prev.map(p => {
        if (p.id === pollId) {
            return {
                ...p,
                votes: { ...p.votes, [option]: p.votes[option] + 1 },
                totalVotes: p.totalVotes + 1,
                hasVoted: true
            };
        }
        return p;
    }));
    if (window.navigator.vibrate) window.navigator.vibrate(10);
  };

  return (
    <div className="flex-1 p-6 animate-fade-in no-scrollbar overflow-y-auto">
      <div className="flex items-center gap-4 mb-8">
        <button onClick={() => navigate('/profile')} className="p-2 -ml-2 bg-white rounded-full border border-slate-100 shadow-sm">
          <ICONS.ChevronRight size={20} className="rotate-180" />
        </button>
        <h1 className="text-2xl font-bold text-slate-900">Voting & Polls</h1>
      </div>

      <div className="space-y-8 pb-4">
        {activePolls.map((poll) => (
          <div key={poll.id} className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-slate-100">
            <div className="flex items-center justify-between mb-6">
                <span className="bg-indigo-50 text-indigo-500 text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider">ONGOING</span>
                <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">ENDS: {poll.endDate}</span>
            </div>

            <h2 className="text-xl font-bold text-slate-900 mb-8 leading-snug">{poll.question}</h2>

            <div className="space-y-4 mb-8">
              {poll.options.map((option) => {
                const percentage = Math.round((poll.votes[option] / poll.totalVotes) * 100);
                return (
                  <button
                    key={option}
                    disabled={poll.hasVoted}
                    onClick={() => handleVote(poll.id, option)}
                    className="w-full relative h-14 group transition-transform active:scale-[0.98]"
                  >
                    <div className={`absolute inset-0 rounded-2xl border transition-all ${
                        poll.hasVoted ? 'bg-slate-50 border-transparent' : 'bg-white border-slate-100 group-hover:border-[#0088CC]'
                    }`}>
                        {poll.hasVoted && (
                            <div 
                                className="h-full bg-blue-100/50 rounded-2xl transition-all duration-1000 ease-out" 
                                style={{ width: `${percentage}%` }}
                            ></div>
                        )}
                    </div>
                    <div className="absolute inset-0 px-5 flex items-center justify-between">
                      <span className={`text-sm font-bold ${poll.hasVoted ? 'text-slate-900' : 'text-slate-600'}`}>{option}</span>
                      {poll.hasVoted && <span className="text-sm font-black text-[#0088CC]">{percentage}%</span>}
                    </div>
                  </button>
                );
              })}
            </div>

            <div className="flex items-center justify-center gap-2 pt-4 border-t border-slate-50">
                <ICONS.Vote size={16} className="text-slate-300" />
                <span className="text-xs font-bold text-slate-300 uppercase tracking-widest">{poll.totalVotes} TOTAL VOTES</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default PollsView;

