const BottomNav = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const currentPath = location.pathname;

  // Hide nav on specific sub-pages if needed
  const hideNav = ['/profile/hostel', '/profile/edit', '/profile/help', '/admin'].some(p => currentPath.startsWith(p));
  if (hideNav) return null;

  const tabs = [
    { path: '/', label: 'Home', Icon: ICONS.Home },
    { path: '/schedule', label: 'Schedule', Icon: ICONS.Schedule },
    { path: '/clubs', label: 'Clubs', Icon: ICONS.Clubs },
    { path: '/library', label: 'Library', Icon: ICONS.Library },
    { path: '/profile', label: 'Profile', Icon: ICONS.Profile },
  ];

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 px-6 py-3 flex justify-between items-center z-50 shadow-[0_-2px_10px_rgba(0,0,0,0.02)]">
      {tabs.map((tab) => {
        const isActive = currentPath === tab.path || (tab.path !== '/' && currentPath.startsWith(tab.path));
        return (
          <button
            key={tab.path}
            onClick={() => {
              navigate(tab.path);
              if (window.navigator.vibrate) window.navigator.vibrate(5);
            }}
            className="flex flex-col items-center gap-1 transition-all duration-200"
          >
            <tab.Icon
              size={24}
              color={isActive ? COLORS.primary : COLORS.muted}
              strokeWidth={isActive ? 2.5 : 2}
            />
            <span
              className={`text-[10px] font-medium ${
                isActive ? 'text-[#0088CC]' : 'text-slate-400'
              }`}
            >
              {tab.label}
            </span>
          </button>
        );
      })}
    </div>
  );
};

const App: React.FC = () => {
  const [user, setUser] = useState(initialUser);

  return (
    <Router>
      <div className="max-w-md mx-auto min-h-screen pb-24 relative shadow-xl bg-slate-50 overflow-hidden flex flex-col">
        <Routes>
          <Route path="/" element={<HomeView />} />
          <Route path="/schedule" element={<ScheduleView />} />
          <Route path="/clubs" element={<ClubsView />} />
