}

const ProfileView: React.FC<ProfileProps> = ({ user }) => {
  const navigate = useNavigate();
  const [isDarkMode, setIsDarkMode] = useState(false);

  const sections = [
    {
      title: 'QUICK ACTIONS',
      items: [
        { label: 'Hostel Booking', sub: 'Book your accommodation', Icon: ICONS.Building, path: '/profile/hostel', iconBg: 'bg-emerald-50', iconColor: 'text-emerald-500' },
        { label: 'Voting & Polls', sub: 'Participate in campus polls', Icon: ICONS.Vote, path: '/profile/polls', iconBg: 'bg-indigo-50', iconColor: 'text-indigo-500', badge: '3' },
      ]
    },
    {
      title: 'SETTINGS',
      items: [
        { label: 'Edit Profile', sub: 'Update your details', Icon: ICONS.User, path: '/profile/edit', iconBg: 'bg-blue-50', iconColor: 'text-blue-500' },
        { label: 'Appearance', sub: isDarkMode ? 'Dark Mode On' : 'Light Mode On', Icon: ICONS.Search, path: 'appearance', iconBg: 'bg-purple-50', iconColor: 'text-purple-500', isToggle: true },
        { label: 'Help & Support', Icon: ICONS.HelpCircle, path: '/profile/help', iconBg: 'bg-slate-50', iconColor: 'text-slate-500' },
      ]
    }
  ];

  // Admin section
  if (user.role === 'admin') {
    sections.unshift({
      title: 'ADMINISTRATION',
      items: [
        { label: 'Admin Dashboard', sub: 'Manage campus data', Icon: ICONS.Shield, path: '/admin', iconBg: 'bg-red-50', iconColor: 'text-red-500' },
      ]
    });
  }

  const handleAction = (item: any) => {
    if (item.isToggle) {
        setIsDarkMode(!isDarkMode);
        if (window.navigator.vibrate) window.navigator.vibrate(10);
        return;
    }
    if (item.path !== '#') navigate(item.path);
  };

  return (
    <div className={`flex-1 p-6 animate-fade-in overflow-y-auto no-scrollbar transition-colors duration-500 ${isDarkMode ? 'bg-slate-900 text-white' : ''}`}>
      {/* Header Profile */}
      <div className="flex items-center gap-5 mb-8">
        <div className="relative group cursor-pointer" onClick={() => navigate('/profile/edit')}>
            <img src={user.profileImage} className="w-20 h-20 rounded-[2.5rem] object-cover ring-4 ring-white shadow-xl shadow-slate-200 transition-transform group-active:scale-95" />
            <div className="absolute -bottom-1 -right-1 w-6 h-6 bg-[#0088CC] rounded-full border-2 border-white flex items-center justify-center">
                <div className="w-1 h-1 bg-white rounded-full"></div>
            </div>
        </div>
        <div className="flex-1">
          <h1 className={`text-xl font-bold leading-tight ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>{user.name}</h1>
          <p className="text-slate-400 text-sm mb-2">{user.email}</p>
          <span className="bg-blue-100 text-[#0088CC] px-3 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider">{user.role}</span>
        </div>
      </div>

      {/* Stats Card */}
      <div className={`${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-100'} rounded-3xl p-5 shadow-sm border mb-8 flex flex-col gap-4`}>
        <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400">
                <ICONS.FileText size={20} />
            </div>
            <div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Student Information</p>
                <p className={`text-sm font-bold ${isDarkMode ? 'text-slate-200' : 'text-slate-800'}`}>{user.program || 'Not set'}</p>
            </div>
        </div>
        <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400">
                <ICONS.Info size={20} />
            </div>
            <div>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Student ID</p>
                <p className={`text-sm font-bold ${isDarkMode ? 'text-slate-200' : 'text-slate-800'}`}>{user.studentId || 'Not set'}</p>
            </div>
        </div>
      </div>

      {/* Menu Sections */}
      <div className="space-y-8">
        {sections.map((section) => (
          <div key={section.title}>
            <h2 className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-4 px-1">{section.title}</h2>
            <div className="space-y-3">
              {section.items.map((item) => (
                <button
                  key={item.label}
                  onClick={() => handleAction(item)}
                  className={`w-full ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-100'} rounded-3xl p-4 shadow-sm border flex items-center gap-4 group active:scale-[0.98] transition-transform`}
                >
                  <div className={`w-12 h-12 ${item.iconBg} rounded-2xl flex items-center justify-center ${item.iconColor}`}>
                    <item.Icon size={20} />
                  </div>
                  <div className="flex-1 text-left">
                    <h3 className={`font-bold text-sm leading-none mb-1.5 ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>{item.label}</h3>
                    {item.sub && <p className="text-slate-400 text-[10px] font-medium">{item.sub}</p>}
                  </div>
                  <div className="flex items-center gap-2">
                    {item.badge && <span className="bg-red-500 text-white w-5 h-5 flex items-center justify-center rounded-full text-[10px] font-bold">{item.badge}</span>}
                    {item.isToggle ? (
                        <div className={`w-10 h-6 rounded-full p-1 transition-colors ${isDarkMode ? 'bg-[#0088CC]' : 'bg-slate-200'}`}>
                            <div className={`w-4 h-4 bg-white rounded-full transition-transform ${isDarkMode ? 'translate-x-4' : ''}`}></div>
                        </div>
                    ) : (
                        <ICONS.ChevronRight size={18} className="text-slate-300 group-hover:text-[#0088CC] transition-colors" />
                    )}
                  </div>
                </button>
              ))}
            </div>
          </div>
        ))}

        <button className={`w-full ${isDarkMode ? 'bg-slate-800' : 'bg-white'} rounded-3xl p-5 border border-red-50 flex items-center gap-4 active:scale-[0.98] transition-transform mb-8`}>
          <div className="w-12 h-12 bg-red-50 rounded-2xl flex items-center justify-center text-red-500">
            <ICONS.LogOut size={20} />
          </div>
          <span className="font-bold text-red-500">Log Out</span>
        </button>

        <div className="flex flex-col items-center justify-center pb-8">
            <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">Merix Campus v1.0.0</p>
        </div>
      </div>
    </div>
  );
};

export default ProfileView;

