import React, { useState } from 'react';
import { HashRouter as Router, Routes, Route, useNavigate, useLocation } from 'react-router-dom';
import { ICONS, COLORS } from './constants';
import HomeView from './views/Home';
import ScheduleView from './views/Schedule';
import ClubsView from './views/Clubs';
import LibraryView from './views/Library';
import ProfileView from './views/Profile';
import HostelBookingView from './views/HostelBooking';
import PollsView from './views/Polls';
import EditProfileView from './views/EditProfile';
import HelpSupportView from './views/HelpSupport';
import AdminDashboardView from './views/AdminDashboard';
import { currentUser as initialUser, initialPolls, initialSchedules, initialAnnouncements } from './mockData';

const BottomNav = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const currentPath = location.pathname;

  const hideNav = ['/profile/hostel', '/profile/edit', '/profile/help', '/admin'].some(p => currentPath.startsWith(p));
  if (hideNav) return null;

  const tabs = [
    { path: '/', label: 'Home', Icon: ICONS.Home },
    { path: '/schedule', label: 'Schedule', Icon: ICONS.Schedule },
    { path: '/clubs', label: 'Clubs', Icon: ICONS.Clubs },
    { path: '/library', label: 'Library', Icon: ICONS.Library },
    { path: '/profile', label: 'Profile', Icon: ICONS.Profile },
  ];

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 px-6 py-3 flex justify-between items-center z-50 shadow-[0_-2px_10px_rgba(0,0,0,0.02)]">
      {tabs.map((tab) => {
        const isActive = currentPath === tab.path || (tab.path !== '/' && currentPath.startsWith(tab.path));
        return (
          <button
            key={tab.path}
            onClick={() => {
              navigate(tab.path);
              if (window.navigator.vibrate) window.navigator.vibrate(5);
            }}
            className="flex flex-col items-center gap-1 transition-all duration-200"
          >
            <tab.Icon
              size={24}
              color={isActive ? COLORS.primary : COLORS.muted}
              strokeWidth={isActive ? 2.5 : 2}
            />
            <span
              className={`text-[10px] font-medium ${
                isActive ? 'text-[#0088CC]' : 'text-slate-400'
              }`}
            >
              {tab.label}
            </span>
          </button>
        );
      })}
    </div>
  );
};

const App: React.FC = () => {
  const [user, setUser] = useState(initialUser);
  const [polls, setPolls] = useState(initialPolls);
  const [schedules, setSchedules] = useState(initialSchedules);
  const [announcements, setAnnouncements] = useState(initialAnnouncements);

  return (
    <Router>
      <div className="max-w-md mx-auto min-h-screen pb-24 relative shadow-xl bg-slate-50 overflow-hidden flex flex-col">
        <Routes>
          <Route path="/" element={<HomeView announcements={announcements} schedules={schedules} />} />
          <Route path="/schedule" element={<ScheduleView schedules={schedules} />} />
          <Route path="/clubs" element={<ClubsView />} />
          <Route path="/library" element={<LibraryView />} />
          <Route path="/profile" element={<ProfileView user={user} pollsCount={polls.length} />} />
          <Route path="/profile/edit" element={<EditProfileView user={user} onUpdate={setUser} />} />
          <Route path="/profile/help" element={<HelpSupportView />} />
          <Route path="/profile/hostel" element={<HostelBookingView user={user} />} />
          <Route path="/profile/polls" element={<PollsView polls={polls} onVote={(id, option) => {
              setPolls(prev => prev.map(p => p.id === id ? { ...p, hasVoted: true, totalVotes: p.totalVotes + 1, votes: { ...p.votes, [option]: (p.votes[option] || 0) + 1 } } : p));
          }} />} />
          <Route path="/admin" element={<AdminDashboardView 
            polls={polls} 
            setPolls={setPolls} 
            schedules={schedules} 
            setSchedules={setSchedules}
            announcements={announcements}
            setAnnouncements={setAnnouncements}
          />} />
        </Routes>
        <BottomNav />
      </div>
    </Router>
  );
};

export default App;

