import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { Poll, ClassSchedule, Announcement } from '../types';

interface AdminDashboardProps {
  polls: Poll[];
  setPolls: React.Dispatch<React.SetStateAction<Poll[]>>;
  schedules: ClassSchedule[];
  setSchedules: React.Dispatch<React.SetStateAction<ClassSchedule[]>>;
  announcements: Announcement[];
  setAnnouncements: React.Dispatch<React.SetStateAction<Announcement[]>>;
}

const AdminDashboardView: React.FC<AdminDashboardProps> = ({ 
  polls, setPolls, schedules, setSchedules, announcements, setAnnouncements 
}) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('Schedules');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Form states
  const [newPoll, setNewPoll] = useState({ question: '', options: ['', ''] });
  const [newSchedule, setNewSchedule] = useState({ 
    course_id: '', course_name: '', instructor: '', day: 'Monday', start: '08:00', end: '10:00', location: '' 
  });

  const handleDeleteSchedule = (id: string) => {
    setSchedules(prev => prev.filter(s => s.id !== id));
  };

  const handleDeletePoll = (id: string) => {
    setPolls(prev => prev.filter(p => p.id !== id));
  };

  const handleCreateSchedule = () => {
    const item: ClassSchedule = {
      id: Math.random().toString(36).substr(2, 9),
      course_id: newSchedule.course_id,
      course_name: newSchedule.course_name,
      instructor_name: newSchedule.instructor,
      day_of_week: newSchedule.day,
      start_time: newSchedule.start,
      end_time: newSchedule.end,
      location: newSchedule.location,
      semester: '1st SEM 2024'
    };
    setSchedules([...schedules, item]);
    setIsModalOpen(false);
  };

  const handleCreatePoll = () => {
    const item: Poll = {
      id: Math.random().toString(36).substr(2, 9),
      question: newPoll.question,
      options: newPoll.options.filter(o => o.trim() !== ''),
      votes: {},
      totalVotes: 0,
      hasVoted: false,
      endDate: '2024-12-31'
    };
    setPolls([...polls, item]);
    setIsModalOpen(false);
  };

  return (
    <div className="flex-1 bg-slate-50 flex flex-col animate-fade-in relative h-full">
      <div className="p-6 bg-white flex items-center justify-between shadow-sm">
        <button onClick={() => navigate('/profile')} className="p-2 -ml-2 hover:bg-slate-50 rounded-full transition-colors">
          <ICONS.ChevronRight size={24} className="rotate-180 text-slate-600" />
        </button>
        <h1 className="font-black text-slate-900 uppercase tracking-widest text-sm">Campus Admin</h1>
        <div className="w-10"></div>
      </div>

      <div className="p-6 space-y-8 overflow-y-auto no-scrollbar flex-1 pb-10">
        {/* Quick Stats */}
        <div className="grid grid-cols-3 gap-3">
            <div className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm text-center">
                <p className="text-xl font-black text-[#0088CC]">{schedules.length}</p>
                <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mt-1">Classes</p>
            </div>
            <div className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm text-center">
                <p className="text-xl font-black text-indigo-500">{polls.length}</p>
                <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mt-1">Polls</p>
            </div>
            <div className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm text-center">
                <p className="text-xl font-black text-red-500">{announcements.length}</p>
                <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mt-1">Updates</p>
            </div>
        </div>

        {/* Action Tabs */}
        <div className="flex bg-white rounded-2xl p-1 shadow-sm border border-slate-100">
            {['Schedules', 'Polls', 'Announcements'].map(t => (
                <button 
                    key={t}
                    onClick={() => setActiveTab(t)}
                    className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${
                        activeTab === t ? 'bg-[#0088CC] text-white shadow-lg' : 'text-slate-400'
                    }`}
                >
                    {t}
                </button>
            ))}
        </div>

        {/* Manage Content */}
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <h3 className="text-sm font-black text-slate-900 uppercase tracking-[0.2em]">{activeTab} Manager</h3>
                <button 
                    onClick={() => setIsModalOpen(true)}
                    className="bg-[#0088CC] text-white w-10 h-10 rounded-2xl flex items-center justify-center shadow-lg active:scale-90 transition-transform"
                >
                    <span className="text-2xl font-light">+</span>
                </button>
            </div>

            <div className="space-y-4">
                {activeTab === 'Schedules' && schedules.map(s => (
                    <div key={s.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4 group">
                        <div className="w-10 h-10 bg-blue-50 text-[#0088CC] rounded-xl flex items-center justify-center">
                            <ICONS.Calendar size={18} />
                        </div>
                        <div className="flex-1">
                            <h4 className="font-bold text-sm text-slate-800">{s.course_id}: {s.course_name}</h4>
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{s.day_of_week} • {s.start_time}</p>
                        </div>
                        <button onClick={() => handleDeleteSchedule(s.id)} className="text-slate-300 hover:text-red-500 transition-colors p-2">
                            <ICONS.LogOut size={16} className="rotate-90" />
                        </button>
                    </div>
                ))}

                {activeTab === 'Polls' && polls.map(p => (
                    <div key={p.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4 group">
                        <div className="w-10 h-10 bg-indigo-50 text-indigo-500 rounded-xl flex items-center justify-center">
                            <ICONS.Vote size={18} />
                        </div>
                        <div className="flex-1">
                            <h4 className="font-bold text-sm text-slate-800">{p.question}</h4>
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{p.totalVotes} votes recorded</p>
                        </div>
                        <button onClick={() => handleDeletePoll(p.id)} className="text-slate-300 hover:text-red-500 transition-colors p-2">
                            <ICONS.LogOut size={16} className="rotate-90" />
                        </button>
                    </div>
                ))}

                {activeTab === 'Announcements' && announcements.map(a => (
                    <div key={a.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4 group">
                        <div className="w-10 h-10 bg-red-50 text-red-500 rounded-xl flex items-center justify-center">
                            <ICONS.Bell size={18} />
                        </div>
                        <div className="flex-1">
                            <h4 className="font-bold text-sm text-slate-800">{a.title}</h4>
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{a.category}</p>
                        </div>
                        <button className="text-slate-300 hover:text-red-500 transition-colors p-2">
                            <ICONS.LogOut size={16} className="rotate-90" />
                        </button>
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* Creation Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-end animate-fade-in">
            <div className="w-full max-w-md mx-auto bg-white rounded-t-[3rem] p-8 space-y-6">
                <div className="flex justify-between items-center mb-2">
                    <h2 className="text-xl font-black text-slate-900 uppercase tracking-widest">Create {activeTab.slice(0, -1)}</h2>
                    <button onClick={() => setIsModalOpen(false)} className="text-slate-400">✕</button>
                </div>

                {activeTab === 'Schedules' && (
                    <div className="space-y-4">
                        <input type="text" placeholder="Course ID (e.g. CS101)" className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newSchedule.course_id} onChange={e => setNewSchedule({...newSchedule, course_id: e.target.value})} />
                        <input type="text" placeholder="Course Name" className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newSchedule.course_name} onChange={e => setNewSchedule({...newSchedule, course_name: e.target.value})} />
                        <div className="grid grid-cols-2 gap-3">
                            <select className="bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newSchedule.day} onChange={e => setNewSchedule({...newSchedule, day: e.target.value})}>
                                <option>Monday</option><option>Tuesday</option><option>Wednesday</option><option>Thursday</option><option>Friday</option>
                            </select>
                            <input type="text" placeholder="Location" className="bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newSchedule.location} onChange={e => setNewSchedule({...newSchedule, location: e.target.value})} />
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                            <input type="time" className="bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newSchedule.start} onChange={e => setNewSchedule({...newSchedule, start: e.target.value})} />
                            <input type="time" className="bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newSchedule.end} onChange={e => setNewSchedule({...newSchedule, end: e.target.value})} />
                        </div>
                        <button onClick={handleCreateSchedule} className="w-full bg-[#0088CC] text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-lg">Save Timetable Entry</button>
                    </div>
                )}

                {activeTab === 'Polls' && (
                    <div className="space-y-4">
                        <input type="text" placeholder="Question" className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newPoll.question} onChange={e => setNewPoll({...newPoll, question: e.target.value})} />
                        <div className="space-y-2">
                            {newPoll.options.map((opt, idx) => (
                                <input key={idx} type="text" placeholder={`Option ${idx + 1}`} className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" value={opt} onChange={e => {
                                    const opts = [...newPoll.options];
                                    opts[idx] = e.target.value;
                                    setNewPoll({...newPoll, options: opts});
                                }} />
                            ))}
                            <button onClick={() => setNewPoll({...newPoll, options: [...newPoll.options, '']})} className="text-xs font-bold text-[#0088CC] uppercase tracking-widest ml-1">+ Add Option</button>
                        </div>
                        <button onClick={handleCreatePoll} className="w-full bg-[#0088CC] text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-lg">Launch Poll</button>
                    </div>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboardView;

import React from 'react';
import { useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { Poll } from '../types';

interface PollsViewProps {
  polls: Poll[];
  onVote: (pollId: string, option: string) => void;
}

const PollsView: React.FC<PollsViewProps> = ({ polls, onVote }) => {
  const navigate = useNavigate();

  return (
    <div className="flex-1 p-6 animate-fade-in no-scrollbar overflow-y-auto">
      <div className="flex items-center gap-4 mb-8">
        <button onClick={() => navigate('/profile')} className="p-2 -ml-2 bg-white rounded-full border border-slate-100 shadow-sm">
          <ICONS.ChevronRight size={20} className="rotate-180" />
        </button>
        <h1 className="text-2xl font-bold text-slate-900">Voting</h1>
      </div>

      <div className="space-y-8 pb-4">
        {polls.length > 0 ? polls.map((poll) => (
          <div key={poll.id} className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-slate-100">
            <div className="flex items-center justify-between mb-6">
                <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider ${poll.hasVoted ? 'bg-emerald-50 text-emerald-500' : 'bg-indigo-50 text-indigo-500'}`}>
                    {poll.hasVoted ? 'VOTED' : 'ONGOING'}
                </span>
                <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">ENDS: {poll.endDate}</span>
            </div>

            <h2 className="text-xl font-bold text-slate-900 mb-8 leading-snug">{poll.question}</h2>

            <div className="space-y-4 mb-8">
              {poll.options.map((option) => {
                const percentage = poll.totalVotes > 0 ? Math.round(((poll.votes[option] || 0) / poll.totalVotes) * 100) : 0;
                return (
                  <button
                    key={option}
                    disabled={poll.hasVoted}
                    onClick={() => onVote(poll.id, option)}
                    className="w-full relative h-14 group transition-transform active:scale-[0.98]"
                  >
                    <div className={`absolute inset-0 rounded-2xl border transition-all ${
                        poll.hasVoted ? 'bg-slate-50 border-transparent' : 'bg-white border-slate-100 group-hover:border-[#0088CC]'
                    }`}>
                        {poll.hasVoted && (
                            <div 
                                className="h-full bg-[#0088CC]/10 rounded-2xl transition-all duration-1000 ease-out" 
                                style={{ width: `${percentage}%` }}
                            ></div>
                        )}
                    </div>
                    <div className="absolute inset-0 px-5 flex items-center justify-between">
                      <span className={`text-sm font-bold ${poll.hasVoted ? 'text-slate-900' : 'text-slate-600'}`}>{option}</span>
                      {poll.hasVoted && <span className="text-sm font-black text-[#0088CC]">{percentage}%</span>}
                    </div>
                  </button>
                );
              })}
            </div>

            <div className="flex items-center justify-center gap-2 pt-4 border-t border-slate-50">
                <ICONS.Vote size={16} className="text-slate-300" />
                <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">{poll.totalVotes} TOTAL PARTICIPANTS</span>
            </div>
          </div>
        )) : (
            <div className="py-20 flex flex-col items-center justify-center text-slate-300">
                <ICONS.Vote size={64} strokeWidth={1} className="mb-4" />
                <p className="text-xs font-bold uppercase tracking-widest">No active polls</p>
            </div>
        )}
      </div>
    </div>
  );
};

