import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { Poll, ClassSchedule, Announcement, Club, HostelBooking, User } from '../types';

interface AdminDashboardProps {
  polls: Poll[];
  setPolls: React.Dispatch<React.SetStateAction<Poll[]>>;
  schedules: ClassSchedule[];
  setSchedules: React.Dispatch<React.SetStateAction<ClassSchedule[]>>;
  announcements: Announcement[];
  setAnnouncements: React.Dispatch<React.SetStateAction<Announcement[]>>;
  clubs: Club[];
  setClubs: React.Dispatch<React.SetStateAction<Club[]>>;
  bookings: HostelBooking[];
  setBookings: React.Dispatch<React.SetStateAction<HostelBooking[]>>;
  students: User[];
  setStudents: React.Dispatch<React.SetStateAction<User[]>>;
}

const AdminDashboardView: React.FC<AdminDashboardProps> = ({ 
  polls, setPolls, schedules, setSchedules, announcements, setAnnouncements,
  clubs, setClubs, bookings, setBookings, students, setStudents
}) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('Schedules');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Form states
  const [newClub, setNewClub] = useState({ name: '', description: '', category: 'Technology', whatsapp: '', image: 'https://picsum.photos/400/200?random=50' });
  const [newSchedule, setNewSchedule] = useState({ course_id: '', course_name: '', instructor: '', day: 'Monday', start: '08:00', end: '10:00', location: '' });
  const [newPoll, setNewPoll] = useState({ question: '', options: ['', ''], endDate: '' });

  const handleCreateClub = () => {
    const club: Club = {
      id: Math.random().toString(36).substr(2, 9),
      name: newClub.name,
      description: newClub.description,
      category: newClub.category,
      members: 0,
      whatsapp_link: newClub.whatsapp,
      image: newClub.image
    };
    setClubs([...clubs, club]);
    setIsModalOpen(false);
    if (window.navigator.vibrate) window.navigator.vibrate(10);
  };

  const handleCreatePoll = () => {
    if (!newPoll.question || newPoll.options.some(o => !o.trim())) return;
    const poll: Poll = {
      id: Math.random().toString(36).substr(2, 9),
      question: newPoll.question,
      options: newPoll.options.filter(o => o.trim() !== ''),
      votes: {},
      totalVotes: 0,
      hasVoted: false,
      endDate: newPoll.endDate || '2024-12-31',
      status: 'open'
    };
    setPolls([...polls, poll]);
    setNewPoll({ question: '', options: ['', ''], endDate: '' });
    setIsModalOpen(false);
    if (window.navigator.vibrate) window.navigator.vibrate(10);
  };

  const handleTogglePollStatus = (id: string) => {
    setPolls(prev => prev.map(p => p.id === id ? { ...p, status: p.status === 'open' ? 'closed' : 'open' } : p));
    if (window.navigator.vibrate) window.navigator.vibrate(5);
  };

  const handleDeletePoll = (id: string) => {
    setPolls(prev => prev.filter(p => p.id !== id));
    if (window.navigator.vibrate) window.navigator.vibrate(15);
  };

  const handleUpdateBooking = (id: string, status: 'confirmed' | 'cancelled') => {
    setBookings(prev => prev.map(b => b.id === id ? { ...b, status } : b));
    if (window.navigator.vibrate) window.navigator.vibrate(5);
  };

  const tabs = ['Schedules', 'Polls', 'Announcements', 'Clubs', 'Bookings', 'Students'];

  return (
    <div className="flex-1 bg-slate-50 flex flex-col animate-fade-in relative h-full">
      <div className="p-6 bg-white flex items-center justify-between shadow-sm">
        <button onClick={() => navigate('/profile')} className="p-2 -ml-2 hover:bg-slate-50 rounded-full transition-colors">
          <ICONS.ChevronRight size={24} className="rotate-180 text-slate-600" />
        </button>
        <h1 className="font-black text-slate-900 uppercase tracking-widest text-xs">Campus Admin</h1>
        <div className="w-10"></div>
      </div>

      <div className="p-6 space-y-6 overflow-y-auto no-scrollbar flex-1 pb-10">
        <div className="flex gap-2 overflow-x-auto no-scrollbar py-2 -mx-6 px-6 bg-white border-b border-slate-100">
            {tabs.map(t => (
                <button 
                    key={t}
                    onClick={() => setActiveTab(t)}
                    className={`py-2 px-4 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all whitespace-nowrap ${
                        activeTab === t ? 'bg-[#0088CC] text-white shadow-lg' : 'text-slate-400 bg-slate-50'
                    }`}
                >
                    {t}
                </button>
            ))}
        </div>

        <div className="flex justify-between items-center">
            <h3 className="text-sm font-black text-slate-900 uppercase tracking-[0.2em]">{activeTab}</h3>
            {['Schedules', 'Polls', 'Announcements', 'Clubs'].includes(activeTab) && (
                <button onClick={() => setIsModalOpen(true)} className="bg-[#0088CC] text-white w-10 h-10 rounded-2xl flex items-center justify-center shadow-lg active:scale-90 transition-transform">
                    <span className="text-2xl font-light">+</span>
                </button>
            )}
        </div>

        <div className="space-y-4">
            {activeTab === 'Students' && students.map(s => (
                <div key={s.id} className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4">
                    <img src={`https://ui-avatars.com/api/?name=${s.name}&background=random`} className="w-10 h-10 rounded-full" />
                    <div className="flex-1">
                        <h4 className="font-bold text-sm text-slate-900">{s.name}</h4>
                        <p className="text-[10px] text-slate-400 font-bold uppercase">{s.studentId} • {s.program}</p>
                    </div>
                    <span className={`text-[8px] font-black px-2 py-0.5 rounded-full uppercase ${s.gender === 'male' ? 'bg-blue-50 text-blue-500' : 'bg-pink-50 text-pink-500'}`}>{s.gender}</span>
                </div>
            ))}

            {activeTab === 'Bookings' && bookings.map(b => (
                <div key={b.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm space-y-4">
                    <div className="flex justify-between items-start">
                        <div>
                            <h4 className="font-bold text-sm text-slate-900">{b.userName}</h4>
                            <p className="text-[10px] text-slate-400 font-bold uppercase">{b.hostelName} • Room {b.roomNumber}</p>
                        </div>
                        <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider ${
                            b.status === 'confirmed' ? 'bg-emerald-50 text-emerald-500' : 
                            b.status === 'pending' ? 'bg-amber-50 text-amber-500' : 'bg-red-50 text-red-500'
                        }`}>{b.status}</span>
                    </div>
                    {b.status === 'pending' && (
                        <div className="flex gap-2 pt-2 border-t border-slate-50">
                            <button onClick={() => handleUpdateBooking(b.id, 'confirmed')} className="flex-1 bg-emerald-500 text-white py-2 rounded-xl text-[10px] font-black uppercase tracking-widest">Confirm</button>
                            <button onClick={() => handleUpdateBooking(b.id, 'cancelled')} className="flex-1 bg-red-500 text-white py-2 rounded-xl text-[10px] font-black uppercase tracking-widest">Cancel</button>
                        </div>
                    )}
                </div>
            ))}

            {activeTab === 'Clubs' && clubs.map(c => (
                <div key={c.id} className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4">
                    <img src={c.image} className="w-12 h-12 rounded-2xl object-cover" />
                    <div className="flex-1">
                        <h4 className="font-bold text-sm text-slate-900">{c.name}</h4>
                        <p className="text-[10px] text-slate-400 font-bold uppercase">{c.category} • {c.members} Members</p>
                    </div>
                    <button onClick={() => setClubs(clubs.filter(cl => cl.id !== c.id))} className="text-red-500 p-2 active:scale-90 transition-transform"><ICONS.LogOut size={16} className="rotate-90" /></button>
                </div>
            ))}

            {activeTab === 'Polls' && polls.map(p => (
                <div key={p.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm space-y-4">
                    <div className="flex justify-between items-start">
                        <div className="flex-1 pr-4">
                            <h4 className="font-bold text-sm text-slate-900 leading-tight mb-1">{p.question}</h4>
                            <div className="flex items-center gap-2">
                                <span className={`text-[8px] font-black px-2 py-0.5 rounded-full uppercase ${p.status === 'open' ? 'bg-emerald-50 text-emerald-500' : 'bg-slate-100 text-slate-400'}`}>
                                    {p.status}
                                </span>
                                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{p.totalVotes} votes</p>
                            </div>
                        </div>
                        <div className="flex gap-2">
                             <button 
                                onClick={() => handleTogglePollStatus(p.id)}
                                title={p.status === 'open' ? 'Close Poll' : 'Re-open Poll'}
                                className={`w-8 h-8 rounded-xl flex items-center justify-center transition-colors ${p.status === 'open' ? 'bg-amber-50 text-amber-500 hover:bg-amber-100' : 'bg-emerald-50 text-emerald-500 hover:bg-emerald-100'}`}
                             >
                                <ICONS.Shield size={16} />
                             </button>
                             <button 
                                onClick={() => handleDeletePoll(p.id)}
                                className="w-8 h-8 bg-red-50 text-red-500 rounded-xl flex items-center justify-center hover:bg-red-100 transition-colors"
                             >
                                <ICONS.LogOut size={16} className="rotate-90" />
                             </button>
                        </div>
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                        {p.options.slice(0, 4).map(opt => (
                            <div key={opt} className="bg-slate-50 rounded-lg p-2 text-[10px] font-medium text-slate-500 flex justify-between">
                                <span className="truncate">{opt}</span>
                                <span className="font-bold text-slate-800">{p.votes[opt] || 0}</span>
                            </div>
                        ))}
                    </div>
                </div>
            ))}

            {activeTab === 'Schedules' && schedules.map(s => (
                <div key={s.id} className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4">
                    <div className="w-10 h-10 bg-blue-50 text-[#0088CC] rounded-xl flex items-center justify-center"><ICONS.Calendar size={18} /></div>
                    <div className="flex-1">
                        <h4 className="font-bold text-sm text-slate-900">{s.course_id}: {s.course_name}</h4>
                        <p className="text-[10px] text-slate-400 font-bold uppercase">{s.day_of_week} • {s.start_time}</p>
                    </div>
                    <button onClick={() => setSchedules(schedules.filter(sc => sc.id !== s.id))} className="text-red-500 p-2"><ICONS.LogOut size={16} className="rotate-90" /></button>
                </div>
            ))}
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-end animate-fade-in">
            <div className="w-full max-w-md mx-auto bg-white rounded-t-[3rem] p-8 space-y-6 max-h-[90vh] overflow-y-auto no-scrollbar shadow-2xl">
                <div className="flex justify-between items-center">
                    <h2 className="text-xl font-black text-slate-900 uppercase tracking-widest">Create {activeTab.slice(0, -1)}</h2>
                    <button onClick={() => setIsModalOpen(false)} className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-400">✕</button>
                </div>

                {activeTab === 'Polls' && (
                    <div className="space-y-5">
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Question</label>
                            <input 
                                type="text" 
                                placeholder="What is your question?" 
                                className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm focus:ring-2 focus:ring-blue-100 transition-all" 
                                value={newPoll.question} 
                                onChange={e => setNewPoll({...newPoll, question: e.target.value})} 
                            />
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Options</label>
                            <div className="space-y-3">
                                {newPoll.options.map((opt, idx) => (
                                    <div key={idx} className="flex gap-2">
                                        <input 
                                            type="text" 
                                            placeholder={`Option ${idx + 1}`} 
                                            className="flex-1 bg-slate-50 border-none rounded-2xl p-4 text-sm focus:ring-2 focus:ring-blue-100 transition-all" 
                                            value={opt} 
                                            onChange={e => {
                                                const opts = [...newPoll.options];
                                                opts[idx] = e.target.value;
                                                setNewPoll({...newPoll, options: opts});
                                            }} 
                                        />
                                        {newPoll.options.length > 2 && (
                                            <button 
                                                onClick={() => setNewPoll({...newPoll, options: newPoll.options.filter((_, i) => i !== idx)})}
                                                className="w-12 bg-red-50 text-red-500 rounded-2xl flex items-center justify-center"
                                            >
                                                <ICONS.LogOut size={16} className="rotate-90" />
                                            </button>
                                        )}
                                    </div>
                                ))}
                                <button 
                                    onClick={() => setNewPoll({...newPoll, options: [...newPoll.options, '']})} 
                                    className="text-xs font-bold text-[#0088CC] uppercase tracking-widest ml-1 flex items-center gap-2"
                                >
                                    <span className="text-lg">+</span> Add Option
                                </button>
                            </div>
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">End Date</label>
                            <input 
                                type="date" 
                                className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" 
                                value={newPoll.endDate} 
                                onChange={e => setNewPoll({...newPoll, endDate: e.target.value})} 
                            />
                        </div>
                        <button 
                            onClick={handleCreatePoll} 
                            disabled={!newPoll.question || newPoll.options.filter(o => o.trim()).length < 2}
                            className={`w-full py-4 rounded-2xl font-black uppercase tracking-widest shadow-lg transition-all ${
                                !newPoll.question || newPoll.options.filter(o => o.trim()).length < 2
                                ? 'bg-slate-200 text-slate-400'
                                : 'bg-[#0088CC] text-white shadow-blue-100 hover:scale-[1.02] active:scale-[0.98]'
                            }`}
                        >
                            Launch Poll
                        </button>
                    </div>
                )}

                {activeTab === 'Clubs' && (
                    <div className="space-y-4">
                        <input type="text" placeholder="Club Name" className="w-full bg-slate-50 rounded-2xl p-4 text-sm" value={newClub.name} onChange={e => setNewClub({...newClub, name: e.target.value})} />
                        <textarea placeholder="Description" className="w-full bg-slate-50 rounded-2xl p-4 text-sm" value={newClub.description} onChange={e => setNewClub({...newClub, description: e.target.value})} />
                        <input type="text" placeholder="WhatsApp Link" className="w-full bg-slate-50 rounded-2xl p-4 text-sm" value={newClub.whatsapp} onChange={e => setNewClub({...newClub, whatsapp: e.target.value})} />
                        <button onClick={handleCreateClub} className="w-full bg-[#0088CC] text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-lg shadow-blue-100">Launch Club</button>
                    </div>
                )}

                {activeTab === 'Schedules' && (
                    <div className="space-y-4">
                        <input type="text" placeholder="Course ID" className="w-full bg-slate-50 rounded-2xl p-4 text-sm" value={newSchedule.course_id} onChange={e => setNewSchedule({...newSchedule, course_id: e.target.value})} />
                        <input type="text" placeholder="Course Name" className="w-full bg-slate-50 rounded-2xl p-4 text-sm" value={newSchedule.course_name} onChange={e => setNewSchedule({...newSchedule, course_name: e.target.value})} />
                        <button onClick={() => {
                            setSchedules([...schedules, { ...newSchedule, id: Math.random().toString(), instructor_name: 'Admin', semester: '2024/25', day_of_week: 'Monday', start_time: '08:00', end_time: '10:00', location: 'Hall A' } as any]);
                            setIsModalOpen(false);
                        }} className="w-full bg-[#0088CC] text-white py-4 rounded-2xl font-black uppercase tracking-widest">Save Schedule</button>
                    </div>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboardView;

import React from 'react';
import { useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { Poll } from '../types';

interface PollsViewProps {
  polls: Poll[];
  onVote: (pollId: string, option: string) => void;
}

const PollsView: React.FC<PollsViewProps> = ({ polls, onVote }) => {
  const navigate = useNavigate();

  return (
    <div className="flex-1 p-6 animate-fade-in no-scrollbar overflow-y-auto">
      <div className="flex items-center gap-4 mb-8">
        <button onClick={() => navigate('/profile')} className="p-2 -ml-2 bg-white rounded-full border border-slate-100 shadow-sm">
          <ICONS.ChevronRight size={20} className="rotate-180" />
        </button>
        <h1 className="text-2xl font-bold text-slate-900">Voting</h1>
      </div>

      <div className="space-y-8 pb-4">
        {polls.length > 0 ? polls.map((poll) => (
          <div key={poll.id} className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-slate-100">
            <div className="flex items-center justify-between mb-6">
                <div className="flex gap-2">
                    <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider ${poll.hasVoted ? 'bg-emerald-50 text-emerald-500' : 'bg-indigo-50 text-indigo-500'}`}>
                        {poll.hasVoted ? 'VOTED' : 'ONGOING'}
                    </span>
                    {poll.status === 'closed' && (
                        <span className="text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider bg-red-50 text-red-500">
                            CLOSED
                        </span>
                    )}
                </div>
                <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">ENDS: {poll.endDate}</span>
            </div>

            <h2 className="text-xl font-bold text-slate-900 mb-8 leading-snug">{poll.question}</h2>

            <div className="space-y-4 mb-8">
              {poll.options.map((option) => {
                const percentage = poll.totalVotes > 0 ? Math.round(((poll.votes[option] || 0) / poll.totalVotes) * 100) : 0;
                const isInteractionDisabled = poll.hasVoted || poll.status === 'closed';

                return (
                  <button
                    key={option}
                    disabled={isInteractionDisabled}
                    onClick={() => onVote(poll.id, option)}
                    className={`w-full relative h-14 group transition-transform ${isInteractionDisabled ? '' : 'active:scale-[0.98]'}`}
                  >
                    <div className={`absolute inset-0 rounded-2xl border transition-all ${
                        isInteractionDisabled ? 'bg-slate-50 border-transparent' : 'bg-white border-slate-100 group-hover:border-[#0088CC]'
                    }`}>
                        {isInteractionDisabled && (
                            <div 
                                className={`h-full ${poll.status === 'closed' ? 'bg-slate-200/50' : 'bg-[#0088CC]/10'} rounded-2xl transition-all duration-1000 ease-out`} 
                                style={{ width: `${percentage}%` }}
                            ></div>
                        )}
                    </div>
                    <div className="absolute inset-0 px-5 flex items-center justify-between">
                      <span className={`text-sm font-bold ${isInteractionDisabled ? 'text-slate-900' : 'text-slate-600'}`}>{option}</span>
                      {isInteractionDisabled && <span className="text-sm font-black text-[#0088CC]">{percentage}%</span>}
                    </div>
                  </button>
                );
              })}
            </div>

            <div className="flex items-center justify-center gap-2 pt-4 border-t border-slate-50">
                <ICONS.Vote size={16} className="text-slate-300" />
                <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">{poll.totalVotes} TOTAL PARTICIPANTS</span>
            </div>
          </div>
        )) : (
            <div className="py-20 flex flex-col items-center justify-center text-slate-300">
                <ICONS.Vote size={64} strokeWidth={1} className="mb-4" />
                <p className="text-xs font-bold uppercase tracking-widest">No active polls</p>
            </div>
        )}
      </div>
    </div>
  );
};

export default PollsView;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { Poll, ClassSchedule, Announcement, Club, HostelBooking, User } from '../types';

interface AdminDashboardProps {
  polls: Poll[];
  setPolls: React.Dispatch<React.SetStateAction<Poll[]>>;
  schedules: ClassSchedule[];
  setSchedules: React.Dispatch<React.SetStateAction<ClassSchedule[]>>;
  announcements: Announcement[];
  setAnnouncements: React.Dispatch<React.SetStateAction<Announcement[]>>;
  clubs: Club[];
  setClubs: React.Dispatch<React.SetStateAction<Club[]>>;
  bookings: HostelBooking[];
  setBookings: React.Dispatch<React.SetStateAction<HostelBooking[]>>;
  students: User[];
  setStudents: React.Dispatch<React.SetStateAction<User[]>>;
}

const AdminDashboardView: React.FC<AdminDashboardProps> = ({ 
  polls, setPolls, schedules, setSchedules, announcements, setAnnouncements,
  clubs, setClubs, bookings, setBookings, students, setStudents
}) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('Schedules');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Form states
  const [newClub, setNewClub] = useState({ name: '', description: '', category: 'Technology', whatsapp: '', image: 'https://picsum.photos/400/200?random=50' });
  const [newSchedule, setNewSchedule] = useState({ course_id: '', course_name: '', instructor: '', day: 'Monday', start: '08:00', end: '10:00', location: '' });
  const [newPoll, setNewPoll] = useState({ question: '', options: ['', ''], endDate: '' });

  const handleCreateClub = () => {
    const club: Club = {
      id: Math.random().toString(36).substr(2, 9),
      name: newClub.name,
      description: newClub.description,
      category: newClub.category,
      members: 0,
      whatsapp_link: newClub.whatsapp,
      image: newClub.image
    };
    setClubs([...clubs, club]);
    setIsModalOpen(false);
    if (window.navigator.vibrate) window.navigator.vibrate(10);
  };

  const handleCreatePoll = () => {
    if (!newPoll.question || newPoll.options.some(o => !o.trim())) return;
    const poll: Poll = {
      id: Math.random().toString(36).substr(2, 9),
      question: newPoll.question,
      options: newPoll.options.filter(o => o.trim() !== ''),
      votes: {},
      totalVotes: 0,
      hasVoted: false,
      endDate: newPoll.endDate || '2024-12-31',
      status: 'open'
    };
    setPolls([...polls, poll]);
    setNewPoll({ question: '', options: ['', ''], endDate: '' });
    setIsModalOpen(false);
    if (window.navigator.vibrate) window.navigator.vibrate(10);
  };

  const handleTogglePollStatus = (id: string) => {
    setPolls(prev => prev.map(p => p.id === id ? { ...p, status: p.status === 'open' ? 'closed' : 'open' } : p));
    if (window.navigator.vibrate) window.navigator.vibrate(5);
  };

  const handleDeletePoll = (id: string) => {
    setPolls(prev => prev.filter(p => p.id !== id));
    if (window.navigator.vibrate) window.navigator.vibrate(15);
  };

  const handleUpdateBooking = (id: string, status: 'confirmed' | 'cancelled') => {
    setBookings(prev => prev.map(b => b.id === id ? { ...b, status } : b));
    if (window.navigator.vibrate) window.navigator.vibrate(10);
  };

  const tabs = ['Schedules', 'Polls', 'Announcements', 'Clubs', 'Hostel Management', 'Students'];

  return (
    <div className="flex-1 bg-slate-50 flex flex-col animate-fade-in relative h-full">
      <div className="p-6 bg-white flex items-center justify-between shadow-sm">
        <button onClick={() => navigate('/profile')} className="p-2 -ml-2 hover:bg-slate-50 rounded-full transition-colors">
          <ICONS.ChevronRight size={24} className="rotate-180 text-slate-600" />
        </button>
        <h1 className="font-black text-slate-900 uppercase tracking-widest text-xs">Campus Admin</h1>
        <div className="w-10"></div>
      </div>

      <div className="p-6 space-y-6 overflow-y-auto no-scrollbar flex-1 pb-10">
        <div className="flex gap-2 overflow-x-auto no-scrollbar py-2 -mx-6 px-6 bg-white border-b border-slate-100">
            {tabs.map(t => (
                <button 
                    key={t}
                    onClick={() => setActiveTab(t)}
                    className={`py-2 px-4 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all whitespace-nowrap ${
                        (activeTab === t || (activeTab === 'Bookings' && t === 'Hostel Management')) ? 'bg-[#0088CC] text-white shadow-lg' : 'text-slate-400 bg-slate-50'
                    }`}
                >
                    {t}
                </button>
            ))}
        </div>

        <div className="flex justify-between items-center">
            <h3 className="text-sm font-black text-slate-900 uppercase tracking-[0.2em]">{activeTab}</h3>
            {['Schedules', 'Polls', 'Announcements', 'Clubs'].includes(activeTab) && (
                <button onClick={() => setIsModalOpen(true)} className="bg-[#0088CC] text-white w-10 h-10 rounded-2xl flex items-center justify-center shadow-lg active:scale-90 transition-transform">
                    <span className="text-2xl font-light">+</span>
                </button>
            )}
        </div>

        <div className="space-y-4">
            {activeTab === 'Students' && students.map(s => (
                <div key={s.id} className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4">
                    <img src={`https://ui-avatars.com/api/?name=${s.name}&background=random`} className="w-10 h-10 rounded-full" />
                    <div className="flex-1">
                        <h4 className="font-bold text-sm text-slate-900">{s.name}</h4>
                        <p className="text-[10px] text-slate-400 font-bold uppercase">{s.studentId} • {s.program}</p>
                    </div>
                    <span className={`text-[8px] font-black px-2 py-0.5 rounded-full uppercase ${s.gender === 'male' ? 'bg-blue-50 text-blue-500' : 'bg-pink-50 text-pink-500'}`}>{s.gender}</span>
                </div>
            ))}

            {(activeTab === 'Hostel Management' || activeTab === 'Bookings') && bookings.map(b => (
                <div key={b.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm space-y-4">
                    <div className="flex justify-between items-start">
                        <div className="flex items-center gap-3">
                            <div className={`w-10 h-10 rounded-2xl flex items-center justify-center ${b.status === 'confirmed' ? 'bg-emerald-50 text-emerald-500' : b.status === 'cancelled' ? 'bg-red-50 text-red-500' : 'bg-amber-50 text-amber-500'}`}>
                                <ICONS.Building size={20} />
                            </div>
                            <div>
                                <h4 className="font-bold text-sm text-slate-900">{b.userName}</h4>
                                <p className="text-[10px] text-slate-400 font-bold uppercase">{b.hostelName} • Room {b.roomNumber}</p>
                            </div>
                        </div>
                        <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider ${
                            b.status === 'confirmed' ? 'bg-emerald-100 text-emerald-600' : 
                            b.status === 'pending' ? 'bg-amber-100 text-amber-600' : 'bg-red-100 text-red-600'
                        }`}>
                            {b.status === 'confirmed' ? 'BOOKED' : b.status === 'cancelled' ? 'REJECTED' : 'PENDING'}
                        </span>
                    </div>

                    {b.status === 'pending' && (
                        <div className="flex gap-2 pt-2 border-t border-slate-50">
                            <button 
                                onClick={() => handleUpdateBooking(b.id, 'confirmed')} 
                                className="flex-1 bg-emerald-500 text-white py-3 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md shadow-emerald-50 active:scale-95 transition-transform"
                            >
                                Accept Booking
                            </button>
                            <button 
                                onClick={() => handleUpdateBooking(b.id, 'cancelled')} 
                                className="flex-1 bg-red-500 text-white py-3 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md shadow-red-50 active:scale-95 transition-transform"
                            >
                                Reject
                            </button>
                        </div>
                    )}
                </div>
            ))}

            {activeTab === 'Clubs' && clubs.map(c => (
                <div key={c.id} className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4">
                    <img src={c.image} className="w-12 h-12 rounded-2xl object-cover" />
                    <div className="flex-1">
                        <h4 className="font-bold text-sm text-slate-900">{c.name}</h4>
                        <p className="text-[10px] text-slate-400 font-bold uppercase">{c.category} • {c.members} Members</p>
                    </div>
                    <button onClick={() => setClubs(clubs.filter(cl => cl.id !== c.id))} className="text-red-500 p-2 active:scale-90 transition-transform"><ICONS.LogOut size={16} className="rotate-90" /></button>
                </div>
            ))}

            {activeTab === 'Polls' && polls.map(p => (
                <div key={p.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm space-y-4">
                    <div className="flex justify-between items-start">
                        <div className="flex-1 pr-4">
                            <h4 className="font-bold text-sm text-slate-900 leading-tight mb-1">{p.question}</h4>
                            <div className="flex items-center gap-2">
                                <span className={`text-[8px] font-black px-2 py-0.5 rounded-full uppercase ${p.status === 'open' ? 'bg-emerald-50 text-emerald-500' : 'bg-slate-100 text-slate-400'}`}>
                                    {p.status}
                                </span>
                                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{p.totalVotes} votes</p>
                            </div>
                        </div>
                        <div className="flex gap-2">
                             <button 
                                onClick={() => handleTogglePollStatus(p.id)}
                                title={p.status === 'open' ? 'Close Poll' : 'Re-open Poll'}
                                className={`w-8 h-8 rounded-xl flex items-center justify-center transition-colors ${p.status === 'open' ? 'bg-amber-50 text-amber-500 hover:bg-amber-100' : 'bg-emerald-50 text-emerald-500 hover:bg-emerald-100'}`}
                             >
                                <ICONS.Shield size={16} />
                             </button>
                             <button 
                                onClick={() => handleDeletePoll(p.id)}
                                className="w-8 h-8 bg-red-50 text-red-500 rounded-xl flex items-center justify-center hover:bg-red-100 transition-colors"
                             >
                                <ICONS.LogOut size={16} className="rotate-90" />
                             </button>
                        </div>
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                        {p.options.slice(0, 4).map(opt => (
                            <div key={opt} className="bg-slate-50 rounded-lg p-2 text-[10px] font-medium text-slate-500 flex justify-between">
                                <span className="truncate">{opt}</span>
                                <span className="font-bold text-slate-800">{p.votes[opt] || 0}</span>
                            </div>
                        ))}
                    </div>
                </div>
            ))}

            {activeTab === 'Schedules' && schedules.map(s => (
                <div key={s.id} className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4">
                    <div className="w-10 h-10 bg-blue-50 text-[#0088CC] rounded-xl flex items-center justify-center"><ICONS.Calendar size={18} /></div>
                    <div className="flex-1">
                        <h4 className="font-bold text-sm text-slate-900">{s.course_id}: {s.course_name}</h4>
                        <p className="text-[10px] text-slate-400 font-bold uppercase">{s.day_of_week} • {s.start_time}</p>
                    </div>
                    <button onClick={() => setSchedules(schedules.filter(sc => sc.id !== s.id))} className="text-red-500 p-2"><ICONS.LogOut size={16} className="rotate-90" /></button>
                </div>
            ))}
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-end animate-fade-in">
            <div className="w-full max-w-md mx-auto bg-white rounded-t-[3rem] p-8 space-y-6 max-h-[90vh] overflow-y-auto no-scrollbar shadow-2xl">
                <div className="flex justify-between items-center">
                    <h2 className="text-xl font-black text-slate-900 uppercase tracking-widest">Create {activeTab.slice(0, -1)}</h2>
                    <button onClick={() => setIsModalOpen(false)} className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-400">✕</button>
                </div>

                {activeTab === 'Polls' && (
                    <div className="space-y-5">
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Question</label>
                            <input 
                                type="text" 
                                placeholder="What is your question?" 
                                className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm focus:ring-2 focus:ring-blue-100 transition-all" 
                                value={newPoll.question} 
                                onChange={e => setNewPoll({...newPoll, question: e.target.value})} 
                            />
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Options</label>
                            <div className="space-y-3">
                                {newPoll.options.map((opt, idx) => (
                                    <div key={idx} className="flex gap-2">
                                        <input 
                                            type="text" 
                                            placeholder={`Option ${idx + 1}`} 
                                            className="flex-1 bg-slate-50 border-none rounded-2xl p-4 text-sm focus:ring-2 focus:ring-blue-100 transition-all" 
                                            value={opt} 
                                            onChange={e => {
                                                const opts = [...newPoll.options];
                                                opts[idx] = e.target.value;
                                                setNewPoll({...newPoll, options: opts});
                                            }} 
                                        />
                                        {newPoll.options.length > 2 && (
                                            <button 
                                                onClick={() => setNewPoll({...newPoll, options: newPoll.options.filter((_, i) => i !== idx)})}
                                                className="w-12 bg-red-50 text-red-500 rounded-2xl flex items-center justify-center"
                                            >
                                                <ICONS.LogOut size={16} className="rotate-90" />
                                            </button>
                                        )}
                                    </div>
                                ))}
                                <button 
                                    onClick={() => setNewPoll({...newPoll, options: [...newPoll.options, '']})} 
                                    className="text-xs font-bold text-[#0088CC] uppercase tracking-widest ml-1 flex items-center gap-2"
                                >
                                    <span className="text-lg">+</span> Add Option
                                </button>
                            </div>
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">End Date</label>
                            <input 
                                type="date" 
                                className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" 
                                value={newPoll.endDate} 
                                onChange={e => setNewPoll({...newPoll, endDate: e.target.value})} 
                            />
                        </div>
                        <button 
                            onClick={handleCreatePoll} 
                            disabled={!newPoll.question || newPoll.options.filter(o => o.trim()).length < 2}
                            className={`w-full py-4 rounded-2xl font-black uppercase tracking-widest shadow-lg transition-all ${
                                !newPoll.question || newPoll.options.filter(o => o.trim()).length < 2
                                ? 'bg-slate-200 text-slate-400'
                                : 'bg-[#0088CC] text-white shadow-blue-100 hover:scale-[1.02] active:scale-[0.98]'
                            }`}
                        >
                            Launch Poll
                        </button>
                    </div>
                )}

                {activeTab === 'Clubs' && (
                    <div className="space-y-4">
                        <input type="text" placeholder="Club Name" className="w-full bg-slate-50 rounded-2xl p-4 text-sm" value={newClub.name} onChange={e => setNewClub({...newClub, name: e.target.value})} />
                        <textarea placeholder="Description" className="w-full bg-slate-50 rounded-2xl p-4 text-sm" value={newClub.description} onChange={e => setNewClub({...newClub, description: e.target.value})} />
                        <input type="text" placeholder="WhatsApp Link" className="w-full bg-slate-50 rounded-2xl p-4 text-sm" value={newClub.whatsapp} onChange={e => setNewClub({...newClub, whatsapp: e.target.value})} />
                        <button onClick={handleCreateClub} className="w-full bg-[#0088CC] text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-lg shadow-blue-100">Launch Club</button>
                    </div>
                )}

                {activeTab === 'Schedules' && (
                    <div className="space-y-4">
                        <input type="text" placeholder="Course ID" className="w-full bg-slate-50 rounded-2xl p-4 text-sm" value={newSchedule.course_id} onChange={e => setNewSchedule({...newSchedule, course_id: e.target.value})} />
                        <input type="text" placeholder="Course Name" className="w-full bg-slate-50 rounded-2xl p-4 text-sm" value={newSchedule.course_name} onChange={e => setNewSchedule({...newSchedule, course_name: e.target.value})} />
                        <button onClick={() => {
                            setSchedules([...schedules, { ...newSchedule, id: Math.random().toString(), instructor_name: 'Admin', semester: '2024/25', day_of_week: 'Monday', start_time: '08:00', end_time: '10:00', location: 'Hall A' } as any]);
                            setIsModalOpen(false);
                        }} className="w-full bg-[#0088CC] text-white py-4 rounded-2xl font-black uppercase tracking-widest">Save Schedule</button>
                    </div>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboardView;

export type Role = 'student' | 'admin';
export type Gender = 'male' | 'female';
export type FileType = 'slides' | 'past_questions' | 'notes' | 'other' | 'books';
export type BookingStatus = 'pending' | 'booked' | 'rejected';
export type TargetType = 'all' | 'program' | 'course';

export interface User {
  id: string;
  name: string;
  email: string;
  role: Role;
  gender: Gender;
  studentId?: string;
  program?: string;
  profileImage?: string;
}

export interface Announcement {
  id: string;
  title: string;
  message: string;
  category: 'URGENT' | 'ACADEMIC' | 'GENERAL' | 'EVENT';
  created_at: string;
  target_type: TargetType;
  is_active: boolean;
}

export interface ClassSchedule {
  id: string;
  course_id: string;
  course_name: string;
  instructor_name: string;
  day_of_week: string;
  start_time: string;
  end_time: string;
  location: string;
  semester: string;
}

export interface Hostel {
  id: string;
  name: string;
  total_floors: number;
  description: string;
  image: string;
}

export interface HostelBooking {
  id: string;
  userId: string;
  userName: string;
  hostelId: string;
  hostelName: string;
  roomNumber: number;
  price: number;
  status: BookingStatus;
  date: string;
}

export interface Club {
  id: string;
  name: string;
  description: string;
  category: string;
  members: number;
  whatsapp_link: string;
  image: string;
}

export interface Poll {
  id: string;
  question: string;
  options: string[];
  votes: Record<string, number>;
  totalVotes: number;
  hasVoted: boolean;
  endDate: string;
  status: 'open' | 'closed';
}

export interface LibraryFile {
  id: string;
  name: string;
  type: FileType;
  course: string;
  size: string;
  date: string;
  downloads: number;
}

export interface HelpRequest {
  id: string;
  subject: string;
  message: string;
  status: 'open' | 'resolved';
  date: string;
}

