import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { Poll, ClassSchedule, Announcement, Club, HostelBooking, User, BookingStatus, TargetType } from '../types';

interface AdminDashboardProps {
  polls: Poll[];
  setPolls: React.Dispatch<React.SetStateAction<Poll[]>>;
  schedules: ClassSchedule[];
  setSchedules: React.Dispatch<React.SetStateAction<ClassSchedule[]>>;
  announcements: Announcement[];
  setAnnouncements: React.Dispatch<React.SetStateAction<Announcement[]>>;
  clubs: Club[];
  setClubs: React.Dispatch<React.SetStateAction<Club[]>>;
  bookings: HostelBooking[];
  setBookings: React.Dispatch<React.SetStateAction<HostelBooking[]>>;
  students: User[];
  setStudents: React.Dispatch<React.SetStateAction<User[]>>;
}

const AdminDashboardView: React.FC<AdminDashboardProps> = ({ 
  polls, setPolls, schedules, setSchedules, announcements, setAnnouncements,
  clubs, setClubs, bookings, setBookings, students, setStudents
}) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('Schedules');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Form states
  const [newClub, setNewClub] = useState({ 
    name: '', 
    description: '', 
    category: 'Technology', 
    whatsapp: '', 
    image: 'https://picsum.photos/400/200?random=' + Math.floor(Math.random() * 100)
  });

  const [newSchedule, setNewSchedule] = useState({ 
    course_id: '', 
    course_name: '', 
    instructor_name: '', 
    day_of_week: 'Monday', 
    start_time: '08:00', 
    end_time: '10:00', 
    location: '',
    semester: '1st SEM 2024/25'
  });

  const [newPoll, setNewPoll] = useState({ question: '', options: ['', ''], endDate: '' });
  const [newAnnouncement, setNewAnnouncement] = useState({ 
    title: '', 
    message: '', 
    category: 'GENERAL' as Announcement['category'], 
    target_type: 'all' as TargetType 
  });

  const handleCreateClub = () => {
    if (!newClub.name || !newClub.description) return;
    const club: Club = {
      id: Math.random().toString(36).substr(2, 9),
      name: newClub.name,
      description: newClub.description,
      category: newClub.category,
      members: 0,
      whatsapp_link: newClub.whatsapp || '#',
      image: newClub.image
    };
    setClubs([club, ...clubs]);
    setNewClub({ name: '', description: '', category: 'Technology', whatsapp: '', image: 'https://picsum.photos/400/200?random=' + Math.floor(Math.random() * 100) });
    setIsModalOpen(false);
    if (window.navigator.vibrate) window.navigator.vibrate(10);
  };

  const handleCreateSchedule = () => {
    if (!newSchedule.course_id || !newSchedule.course_name || !newSchedule.instructor_name || !newSchedule.location) return;
    const schedule: ClassSchedule = {
      id: Math.random().toString(36).substr(2, 9),
      ...newSchedule
    };
    setSchedules([schedule, ...schedules]);
    setNewSchedule({ 
        course_id: '', 
        course_name: '', 
        instructor_name: '', 
        day_of_week: 'Monday', 
        start_time: '08:00', 
        end_time: '10:00', 
        location: '',
        semester: '1st SEM 2024/25'
    });
    setIsModalOpen(false);
    if (window.navigator.vibrate) window.navigator.vibrate(10);
  };

  const handleCreatePoll = () => {
    if (!newPoll.question || newPoll.options.some(o => !o.trim())) return;
    const poll: Poll = {
      id: Math.random().toString(36).substr(2, 9),
      question: newPoll.question,
      options: newPoll.options.filter(o => o.trim() !== ''),
      votes: {},
      totalVotes: 0,
      hasVoted: false,
      endDate: newPoll.endDate || '2024-12-31',
      status: 'open'
    };
    setPolls([...polls, poll]);
    setNewPoll({ question: '', options: ['', ''], endDate: '' });
    setIsModalOpen(false);
    if (window.navigator.vibrate) window.navigator.vibrate(10);
  };

  const handleCreateAnnouncement = () => {
    if (!newAnnouncement.title || !newAnnouncement.message) return;
    const announcement: Announcement = {
      id: Math.random().toString(36).substr(2, 9),
      title: newAnnouncement.title,
      message: newAnnouncement.message,
      category: newAnnouncement.category,
      created_at: new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
      target_type: newAnnouncement.target_type,
      is_active: true
    };
    setAnnouncements([announcement, ...announcements]);
    setNewAnnouncement({ title: '', message: '', category: 'GENERAL', target_type: 'all' });
    setIsModalOpen(false);
    if (window.navigator.vibrate) window.navigator.vibrate(15);
  };

  const handleDeleteAnnouncement = (id: string) => {
    setAnnouncements(prev => prev.filter(a => a.id !== id));
    if (window.navigator.vibrate) window.navigator.vibrate(5);
  };

  const handleTogglePollStatus = (id: string) => {
    setPolls(prev => prev.map(p => p.id === id ? { ...p, status: p.status === 'open' ? 'closed' : 'open' } : p));
    if (window.navigator.vibrate) window.navigator.vibrate(5);
  };

  const handleDeletePoll = (id: string) => {
    setPolls(prev => prev.filter(p => p.id !== id));
    if (window.navigator.vibrate) window.navigator.vibrate(15);
  };

  const handleUpdateBooking = (id: string, status: BookingStatus) => {
    setBookings(prev => prev.map(b => b.id === id ? { ...b, status } : b));
    if (window.navigator.vibrate) window.navigator.vibrate(10);
  };

  const tabs = ['Schedules', 'Polls', 'Announcements', 'Clubs', 'Hostel Management', 'Students'];

  return (
    <div className="flex-1 bg-slate-50 flex flex-col animate-fade-in relative h-full">
      <div className="p-6 bg-white flex items-center justify-between shadow-sm">
        <button onClick={() => navigate('/profile')} className="p-2 -ml-2 hover:bg-slate-50 rounded-full transition-colors">
          <ICONS.ChevronRight size={24} className="rotate-180 text-slate-600" />
        </button>
        <h1 className="font-black text-slate-900 uppercase tracking-widest text-xs">Campus Admin</h1>
        <div className="w-10"></div>
      </div>

      <div className="p-6 space-y-6 overflow-y-auto no-scrollbar flex-1 pb-10">
        <div className="flex gap-2 overflow-x-auto no-scrollbar py-2 -mx-6 px-6 bg-white border-b border-slate-100">
            {tabs.map(t => (
                <button 
                    key={t}
                    onClick={() => setActiveTab(t)}
                    className={`py-2 px-4 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all whitespace-nowrap ${
                        activeTab === t ? 'bg-[#0088CC] text-white shadow-lg' : 'text-slate-400 bg-slate-50'
                    }`}
                >
                    {t}
                </button>
            ))}
        </div>

        <div className="flex justify-between items-center">
            <h3 className="text-sm font-black text-slate-900 uppercase tracking-[0.2em]">{activeTab}</h3>
            {['Schedules', 'Polls', 'Announcements', 'Clubs'].includes(activeTab) && (
                <button onClick={() => setIsModalOpen(true)} className="bg-[#0088CC] text-white w-10 h-10 rounded-2xl flex items-center justify-center shadow-lg active:scale-90 transition-transform">
                    <span className="text-2xl font-light">+</span>
                </button>
            )}
        </div>

        <div className="space-y-4">
            {activeTab === 'Schedules' && schedules.map(s => (
                <div key={s.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm space-y-3">
                    <div className="flex justify-between items-start">
                        <div className="flex items-center gap-3">
                            <div className="w-10 h-10 bg-blue-50 text-[#0088CC] rounded-xl flex items-center justify-center">
                                <ICONS.Calendar size={20} />
                            </div>
                            <div>
                                <h4 className="font-bold text-sm text-slate-900 leading-tight">{s.course_id}: {s.course_name}</h4>
                                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{s.instructor_name}</p>
                            </div>
                        </div>
                        <button onClick={() => setSchedules(schedules.filter(sc => sc.id !== s.id))} className="text-slate-300 hover:text-red-500 transition-colors p-1">
                            <ICONS.LogOut size={16} className="rotate-90" />
                        </button>
                    </div>
                    <div className="flex items-center justify-between pt-2 border-t border-slate-50">
                        <div className="flex items-center gap-3">
                            <span className="bg-slate-50 text-slate-500 px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest">{s.day_of_week}</span>
                            <span className="text-[10px] text-slate-400 font-bold uppercase">{s.start_time} - {s.end_time}</span>
                        </div>
                        <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest flex items-center gap-1">
                            <ICONS.Building size={10} /> {s.location}
                        </span>
                    </div>
                </div>
            ))}

            {activeTab === 'Clubs' && clubs.map(c => (
                <div key={c.id} className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4 group">
                    <img src={c.image} className="w-14 h-14 rounded-2xl object-cover" />
                    <div className="flex-1 min-w-0">
                        <h4 className="font-bold text-sm text-slate-900 truncate">{c.name}</h4>
                        <div className="flex items-center gap-2 mt-0.5">
                            <span className="text-[9px] font-black text-[#0088CC] uppercase tracking-wider">{c.category}</span>
                            <span className="text-[9px] text-slate-300">•</span>
                            <span className="text-[9px] text-slate-400 font-bold uppercase">{c.members} MEMBERS</span>
                        </div>
                    </div>
                    <button onClick={() => setClubs(clubs.filter(cl => cl.id !== c.id))} className="text-slate-300 hover:text-red-500 p-2 active:scale-90 transition-transform">
                        <ICONS.LogOut size={16} className="rotate-90" />
                    </button>
                </div>
            ))}

            {activeTab === 'Announcements' && announcements.map(ann => (
                <div key={ann.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm space-y-3">
                    <div className="flex justify-between items-start">
                        <div className="flex items-center gap-2">
                            <span className={`w-2 h-2 rounded-full ${
                                ann.category === 'URGENT' ? 'bg-red-500' :
                                ann.category === 'ACADEMIC' ? 'bg-emerald-500' : 'bg-blue-500'
                            }`}></span>
                            <span className={`text-[10px] font-black tracking-widest ${
                                ann.category === 'URGENT' ? 'text-red-500' :
                                ann.category === 'ACADEMIC' ? 'text-emerald-500' : 'text-blue-500'
                            }`}>{ann.category}</span>
                            <span className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">• {ann.target_type.toUpperCase()}</span>
                        </div>
                        <button 
                            onClick={() => handleDeleteAnnouncement(ann.id)}
                            className="text-slate-300 hover:text-red-500 transition-colors"
                        >
                            <ICONS.LogOut size={16} className="rotate-90" />
                        </button>
                    </div>
                    <div>
                        <h4 className="font-bold text-slate-900 text-sm mb-1">{ann.title}</h4>
                        <p className="text-slate-500 text-xs leading-relaxed line-clamp-2">{ann.message}</p>
                    </div>
                    <div className="flex justify-between items-center pt-2 border-t border-slate-50">
                        <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{ann.created_at}</span>
                        <div className="flex items-center gap-2">
                            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Active</span>
                            <div className={`w-8 h-4 rounded-full p-0.5 transition-colors ${ann.is_active ? 'bg-blue-100' : 'bg-slate-100'}`}>
                                <div className={`w-3 h-3 rounded-full bg-white transition-transform ${ann.is_active ? 'translate-x-4' : ''}`}></div>
                            </div>
                        </div>
                    </div>
                </div>
            ))}

            {activeTab === 'Students' && students.map(s => (
                <div key={s.id} className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4">
                    <img src={`https://ui-avatars.com/api/?name=${s.name}&background=random`} className="w-10 h-10 rounded-full" />
                    <div className="flex-1">
                        <h4 className="font-bold text-sm text-slate-900">{s.name}</h4>
                        <p className="text-[10px] text-slate-400 font-bold uppercase">{s.studentId} • {s.program}</p>
                    </div>
                    <span className={`text-[8px] font-black px-2 py-0.5 rounded-full uppercase ${s.gender === 'male' ? 'bg-blue-50 text-blue-500' : 'bg-pink-50 text-pink-500'}`}>{s.gender}</span>
                </div>
            ))}

            {(activeTab === 'Hostel Management' || activeTab === 'Bookings') && bookings.map(b => (
                <div key={b.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm space-y-4">
                    <div className="flex justify-between items-start">
                        <div className="flex items-center gap-3">
                            <div className={`w-10 h-10 rounded-2xl flex items-center justify-center ${b.status === 'booked' ? 'bg-emerald-50 text-emerald-500' : b.status === 'rejected' ? 'bg-red-50 text-red-500' : 'bg-amber-50 text-amber-500'}`}>
                                <ICONS.Building size={20} />
                            </div>
                            <div>
                                <h4 className="font-bold text-sm text-slate-900">{b.userName}</h4>
                                <p className="text-[10px] text-slate-400 font-bold uppercase">{b.hostelName} • Room {b.roomNumber}</p>
                            </div>
                        </div>
                        <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider ${
                            b.status === 'booked' ? 'bg-emerald-100 text-emerald-600' : 
                            b.status === 'pending' ? 'bg-amber-100 text-amber-600' : 'bg-red-100 text-red-600'
                        }`}>
                            {b.status === 'booked' ? 'BOOKED' : b.status === 'rejected' ? 'REJECTED' : 'PENDING'}
                        </span>
                    </div>

                    {b.status === 'pending' && (
                        <div className="flex gap-2 pt-2 border-t border-slate-50">
                            <button 
                                onClick={() => handleUpdateBooking(b.id, 'booked')} 
                                className="flex-1 bg-emerald-500 text-white py-3 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md shadow-emerald-50 active:scale-95 transition-transform"
                            >
                                Accept Booking
                            </button>
                            <button 
                                onClick={() => handleUpdateBooking(b.id, 'rejected')} 
                                className="flex-1 bg-red-500 text-white py-3 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md shadow-red-50 active:scale-95 transition-transform"
                            >
                                Reject
                            </button>
                        </div>
                    )}
                </div>
            ))}

            {activeTab === 'Polls' && polls.map(p => (
                <div key={p.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm space-y-4">
                    <div className="flex justify-between items-start">
                        <div className="flex-1 pr-4">
                            <h4 className="font-bold text-sm text-slate-900 leading-tight mb-1">{p.question}</h4>
                            <div className="flex items-center gap-2">
                                <span className={`text-[8px] font-black px-2 py-0.5 rounded-full uppercase ${p.status === 'open' ? 'bg-emerald-50 text-emerald-500' : 'bg-slate-100 text-slate-400'}`}>
                                    {p.status}
                                </span>
                                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{p.totalVotes} votes</p>
                            </div>
                        </div>
                        <div className="flex gap-2">
                             <button 
                                onClick={() => handleTogglePollStatus(p.id)}
                                title={p.status === 'open' ? 'Close Poll' : 'Re-open Poll'}
                                className={`w-8 h-8 rounded-xl flex items-center justify-center transition-colors ${p.status === 'open' ? 'bg-amber-50 text-amber-500 hover:bg-amber-100' : 'bg-emerald-50 text-emerald-500 hover:bg-emerald-100'}`}
                             >
                                <ICONS.Shield size={16} />
                             </button>
                             <button 
                                onClick={() => handleDeletePoll(p.id)}
                                className="w-8 h-8 bg-red-50 text-red-500 rounded-xl flex items-center justify-center hover:bg-red-100 transition-colors"
                             >
                                <ICONS.LogOut size={16} className="rotate-90" />
                             </button>
                        </div>
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                        {p.options.slice(0, 4).map(opt => (
                            <div key={opt} className="bg-slate-50 rounded-lg p-2 text-[10px] font-medium text-slate-500 flex justify-between">
                                <span className="truncate">{opt}</span>
                                <span className="font-bold text-slate-800">{p.votes[opt] || 0}</span>
                            </div>
                        ))}
                    </div>
                </div>
            ))}
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-end animate-fade-in">
            <div className="w-full max-w-md mx-auto bg-white rounded-t-[3rem] p-8 space-y-6 max-h-[90vh] overflow-y-auto no-scrollbar shadow-2xl">
                <div className="flex justify-between items-center">
                    <h2 className="text-xl font-black text-slate-900 uppercase tracking-widest">Create {activeTab.slice(0, -1)}</h2>
                    <button onClick={() => setIsModalOpen(false)} className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-400">✕</button>
                </div>

                {activeTab === 'Clubs' && (
                    <div className="space-y-4">
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Club Name</label>
                            <input type="text" placeholder="E.g. Engineering Society" className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newClub.name} onChange={e => setNewClub({...newClub, name: e.target.value})} />
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Category</label>
                            <select className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm appearance-none" value={newClub.category} onChange={e => setNewClub({...newClub, category: e.target.value})}>
                                <option>Technology</option>
                                <option>Academic</option>
                                <option>Arts</option>
                                <option>Sports</option>
                                <option>Business</option>
                            </select>
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Description</label>
                            <textarea placeholder="Tell us about the club..." className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm resize-none" rows={3} value={newClub.description} onChange={e => setNewClub({...newClub, description: e.target.value})} />
                        </div>
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">WhatsApp Invite Link</label>
