import { 
  initialAnnouncements, 
  initialBookings, 
  initialClubs, 
  initialPolls, 
  initialSchedules, 
  initialStudents,
  currentUser
} from '../mockData';

const DB_KEY = 'merix_upsa_db';

export const db = {
  init: () => {
    if (!localStorage.getItem(DB_KEY)) {
      const initialDb = {
        announcements: initialAnnouncements,
        bookings: initialBookings,
        clubs: initialClubs,
        polls: initialPolls,
        schedules: initialSchedules,
        students: initialStudents,
        user: currentUser
      };
      localStorage.setItem(DB_KEY, JSON.stringify(initialDb));
    }
  },

  get: (key: string) => {
    const data = JSON.parse(localStorage.getItem(DB_KEY) || '{}');
    return data[key] || [];
  },

  save: (key: string, value: any) => {
    const data = JSON.parse(localStorage.getItem(DB_KEY) || '{}');
    data[key] = value;
    localStorage.setItem(DB_KEY, JSON.stringify(data));
  }
};

import { db } from './db';

const LATENCY = 600;

const delay = () => new Promise(resolve => setTimeout(resolve, LATENCY));

export const api = {
  announcements: {
    getAll: async () => {
      await delay();
      return db.get('announcements');
    },
    create: async (item: any) => {
      await delay();
      if (!item.title || !item.message) throw new Error('Title and message are required');
      const items = db.get('announcements');
      const newItem = { ...item, id: Math.random().toString(36).substr(2, 9), created_at: 'Just now', is_active: true };
      db.save('announcements', [newItem, ...items]);
      return newItem;
    },
    delete: async (id: string) => {
      await delay();
      const items = db.get('announcements');
      db.save('announcements', items.filter((i: any) => i.id !== id));
    }
  },

  schedules: {
    getAll: async () => {
      await delay();
      return db.get('schedules');
    },
    create: async (item: any) => {
      await delay();
      if (!item.course_id || !item.course_name) throw new Error('Course details missing');
      const items = db.get('schedules');
      const newItem = { ...item, id: Math.random().toString(36).substr(2, 9) };
      db.save('schedules', [newItem, ...items]);
      return newItem;
    },
    delete: async (id: string) => {
      await delay();
      const items = db.get('schedules');
      db.save('schedules', items.filter((i: any) => i.id !== id));
    }
  },

  clubs: {
    getAll: async () => {
      await delay();
      return db.get('clubs');
    },
    create: async (item: any) => {
      await delay();
      const items = db.get('clubs');
      const newItem = { ...item, id: Math.random().toString(36).substr(2, 9), members: 0 };
      db.save('clubs', [newItem, ...items]);
      return newItem;
    },
    delete: async (id: string) => {
      await delay();
      const items = db.get('clubs');
      db.save('clubs', items.filter((i: any) => i.id !== id));
    }
  },

  polls: {
    getAll: async () => {
      await delay();
      return db.get('polls');
    },
    create: async (item: any) => {
      await delay();
      const items = db.get('polls');
      const newItem = { ...item, id: Math.random().toString(36).substr(2, 9), votes: {}, totalVotes: 0, hasVoted: false, status: 'open' };
      db.save('polls', [newItem, ...items]);
      return newItem;
    },
    vote: async (pollId: string, option: string) => {
      await delay();
      const items = db.get('polls');
      const updated = items.map((p: any) => {
        if (p.id === pollId) {
          return {
            ...p,
            hasVoted: true,
            totalVotes: p.totalVotes + 1,
            votes: { ...p.votes, [option]: (p.votes[option] || 0) + 1 }
          };
        }
        return p;
      });
      db.save('polls', updated);
    },
    delete: async (id: string) => {
      await delay();
      const items = db.get('polls');
      db.save('polls', items.filter((i: any) => i.id !== id));
    },
    toggleStatus: async (id: string) => {
      await delay();
      const items = db.get('polls');
      db.save('polls', items.map((i: any) => i.id === id ? { ...i, status: i.status === 'open' ? 'closed' : 'open' } : i));
    }
  },

  bookings: {
    getAll: async () => {
      await delay();
      return db.get('bookings');
    },
    create: async (item: any) => {
      await delay();
      const items = db.get('bookings');
      const newItem = { ...item, id: Math.random().toString(36).substr(2, 9), status: 'pending', date: new Date().toISOString().split('T')[0] };
      db.save('bookings', [newItem, ...items]);
      return newItem;
    },
    updateStatus: async (id: string, status: string) => {
      await delay();
      const items = db.get('bookings');
      db.save('bookings', items.map((i: any) => i.id === id ? { ...i, status } : i));
    }
  },

  students: {
    getAll: async () => {
      await delay();
      return db.get('students');
    }
  }
};

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, useNavigate, useLocation } from 'react-router-dom';
import { ICONS, COLORS } from './constants';
import HomeView from './views/Home';
import ScheduleView from './views/Schedule';
import ClubsView from './views/Clubs';
import LibraryView from './views/Library';
import ProfileView from './views/Profile';
import HostelBookingView from './views/HostelBooking';
import PollsView from './views/Polls';
import EditProfileView from './views/EditProfile';
import HelpSupportView from './views/HelpSupport';
import AdminDashboardView from './views/AdminDashboard';
