import { api } from './services/api';

const BottomNav = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const currentPath = location.pathname;

  const hideNav = ['/profile/hostel', '/profile/edit', '/profile/help', '/admin'].some(p => currentPath.startsWith(p));
  if (hideNav) return null;

  const tabs = [
    { path: '/', label: 'Home', Icon: ICONS.Home },
    { path: '/schedule', label: 'Schedule', Icon: ICONS.Schedule },
    { path: '/clubs', label: 'Clubs', Icon: ICONS.Clubs },
    { path: '/library', label: 'Library', Icon: ICONS.Library },
    { path: '/profile', label: 'Profile', Icon: ICONS.Profile },
  ];

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 px-6 py-3 flex justify-between items-center z-50 shadow-[0_-2px_10px_rgba(0,0,0,0.02)]">
      {tabs.map((tab) => {
        const isActive = currentPath === tab.path || (tab.path !== '/' && currentPath.startsWith(tab.path));
        return (
          <button
            key={tab.path}
            onClick={() => {
              navigate(tab.path);
              if (window.navigator.vibrate) window.navigator.vibrate(5);
            }}
            className="flex flex-col items-center gap-1 transition-all duration-200"
          >
            <tab.Icon
              size={24}
              color={isActive ? COLORS.primary : COLORS.muted}
              strokeWidth={isActive ? 2.5 : 2}
            />
            <span
              className={`text-[10px] font-medium ${
                isActive ? 'text-[#0088CC]' : 'text-slate-400'
              }`}
            >
              {tab.label}
            </span>
          </button>
        );
      })}
    </div>
  );
};

const GlobalLoader = () => (
  <div className="fixed inset-0 bg-slate-50/80 backdrop-blur-sm z-[200] flex items-center justify-center animate-fade-in">
    <div className="flex flex-col items-center gap-4">
      <div className="w-12 h-12 border-4 border-[#0088CC]/20 border-t-[#0088CC] rounded-full animate-spin"></div>
      <p className="text-[10px] font-black text-[#0088CC] uppercase tracking-widest">Synchronizing...</p>
    </div>
  </div>
);

const App: React.FC = () => {
  const [user, setUser] = useState<any>(null);
  const [polls, setPolls] = useState<any[]>([]);
  const [schedules, setSchedules] = useState<any[]>([]);
  const [announcements, setAnnouncements] = useState<any[]>([]);
  const [clubs, setClubs] = useState<any[]>([]);
  const [bookings, setBookings] = useState<any[]>([]);
  const [students, setStudents] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    db.init();
    refreshAll();
  }, []);

  const refreshAll = async () => {
    setLoading(true);
    try {
      const [u, p, s, a, c, b, stu] = await Promise.all([
        Promise.resolve(db.get('user')),
        api.polls.getAll(),
        api.schedules.getAll(),
        api.announcements.getAll(),
        api.clubs.getAll(),
        api.bookings.getAll(),
        api.students.getAll()
      ]);
      setUser(u);
      setPolls(p);
      setSchedules(s);
      setAnnouncements(a);
      setClubs(c);
      setBookings(b);
      setStudents(stu);
    } catch (err) {
      console.error("Failed to load data", err);
    } finally {
      setLoading(false);
    }
  };

  if (loading && !user) return <GlobalLoader />;

  return (
    <Router>
      <div className="max-w-md mx-auto min-h-screen pb-24 relative shadow-xl bg-slate-50 overflow-hidden flex flex-col">
        {loading && <GlobalLoader />}
        <Routes>
          <Route path="/" element={<HomeView announcements={announcements} schedules={schedules} onRefresh={refreshAll} />} />
          <Route path="/schedule" element={<ScheduleView schedules={schedules} />} />
          <Route path="/clubs" element={<ClubsView clubs={clubs} />} />
          <Route path="/library" element={<LibraryView />} />
          <Route path="/profile" element={<ProfileView user={user} pollsCount={polls.length} />} />
          <Route path="/profile/edit" element={<EditProfileView user={user} onUpdate={(u) => { db.save('user', u); setUser(u); }} />} />
          <Route path="/profile/help" element={<HelpSupportView />} />
          <Route path="/profile/hostel" element={<HostelBookingView user={user} onBook={async (b) => { await api.bookings.create(b); refreshAll(); }} />} />
          <Route path="/profile/polls" element={<PollsView polls={polls} onVote={async (id, option) => { await api.polls.vote(id, option); refreshAll(); }} />} />
          <Route path="/admin" element={<AdminDashboardView 
            polls={polls} 
            schedules={schedules}
            announcements={announcements}
            clubs={clubs}
            bookings={bookings}
            students={students}
            onUpdate={refreshAll}
          />} />
        </Routes>
        <BottomNav />
      </div>
    </Router>
  );
};

export default App;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { Poll, ClassSchedule, Announcement, Club, HostelBooking, User, BookingStatus, TargetType } from '../types';
import { api } from '../services/api';

interface AdminDashboardProps {
  polls: Poll[];
  schedules: ClassSchedule[];
  announcements: Announcement[];
  clubs: Club[];
  bookings: HostelBooking[];
  students: User[];
  onUpdate: () => void;
}

const AdminDashboardView: React.FC<AdminDashboardProps> = ({ 
  polls, schedules, announcements, clubs, bookings, students, onUpdate
}) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('Schedules');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  // Form states
  const [newClub, setNewClub] = useState({ 
    name: '', 
    description: '', 
    category: 'Technology', 
    whatsapp: '', 
    image: 'https://picsum.photos/400/200?random=' + Math.floor(Math.random() * 100)
  });

  const [newSchedule, setNewSchedule] = useState({ 
    course_id: '', 
    course_name: '', 
    instructor_name: '', 
    day_of_week: 'Monday', 
    start_time: '08:00', 
    end_time: '10:00', 
    location: '',
    semester: '1st SEM 2024/25'
  });

  const [newPoll, setNewPoll] = useState({ question: '', options: ['', ''], endDate: '' });
  const [newAnnouncement, setNewAnnouncement] = useState({ 
    title: '', 
    message: '', 
    category: 'GENERAL' as Announcement['category'], 
    target_type: 'all' as TargetType 
  });

  const wrapAction = async (promise: Promise<any>) => {
    setIsProcessing(true);
    try {
      await promise;
      onUpdate();
      setIsModalOpen(false);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateClub = () => wrapAction(api.clubs.create(newClub));
  const handleCreateSchedule = () => wrapAction(api.schedules.create(newSchedule));
  const handleCreatePoll = () => wrapAction(api.polls.create(newPoll));
  const handleCreateAnnouncement = () => wrapAction(api.announcements.create(newAnnouncement));

  const handleDeleteAnnouncement = (id: string) => wrapAction(api.announcements.delete(id));
  const handleDeleteSchedule = (id: string) => wrapAction(api.schedules.delete(id));
  const handleDeletePoll = (id: string) => wrapAction(api.polls.delete(id));
  const handleDeleteClub = (id: string) => wrapAction(api.clubs.delete(id));

  const handleTogglePollStatus = (id: string) => wrapAction(api.polls.toggleStatus(id));
