const BottomNav = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const currentPath = location.pathname;

  const hideNav = ['/profile/hostel', '/profile/edit', '/profile/help', '/admin'].some(p => currentPath.startsWith(p));
  if (hideNav) return null;

  const tabs = [
    { path: '/', label: 'Home', Icon: ICONS.Home },
    { path: '/schedule', label: 'Schedule', Icon: ICONS.Schedule },
    { path: '/clubs', label: 'Clubs', Icon: ICONS.Clubs },
    { path: '/library', label: 'Library', Icon: ICONS.Library },
    { path: '/profile', label: 'Profile', Icon: ICONS.Profile },
  ];

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-lg border-t border-slate-100 px-6 py-3 flex justify-between items-center z-50 shadow-[0_-2px_20px_rgba(0,0,0,0.04)]">
      {tabs.map((tab) => {
        const isActive = currentPath === tab.path || (tab.path !== '/' && currentPath.startsWith(tab.path));
        return (
          <button
            key={tab.path}
            onClick={() => {
              navigate(tab.path);
              if (window.navigator.vibrate) window.navigator.vibrate(5);
            }}
            className="flex flex-col items-center gap-1 transition-all duration-300"
          >
            <tab.Icon
              size={24}
              color={isActive ? COLORS.primary : COLORS.muted}
              strokeWidth={isActive ? 2.5 : 2}
            />
            <span
              className={`text-[10px] font-black uppercase tracking-widest ${
                isActive ? 'text-[#0088CC]' : 'text-slate-400'
              }`}
            >
              {tab.label}
            </span>
          </button>
        );
      })}
    </div>
  );
};

const GlobalLoader = () => (
  <div className="fixed inset-0 bg-white/40 backdrop-blur-[2px] z-[200] flex items-center justify-center animate-fade-in">
    <div className="bg-white/80 p-8 rounded-[3rem] shadow-2xl flex flex-col items-center gap-4">
      <div className="w-12 h-12 border-4 border-[#0088CC]/10 border-t-[#0088CC] rounded-full animate-spin"></div>
      <p className="text-[10px] font-black text-[#0088CC] uppercase tracking-widest animate-pulse">Synchronizing</p>
    </div>
  </div>
);

const Toast = ({ message, type, onClose }: { message: string, type: 'success' | 'error', onClose: () => void }) => {
  useEffect(() => {
    const timer = setTimeout(onClose, 3000);
    return () => clearTimeout(timer);
  }, [onClose]);

  return (
    <div className={`fixed top-6 left-1/2 -translate-x-1/2 z-[300] px-6 py-3 rounded-2xl shadow-xl border flex items-center gap-3 animate-fade-in ${
      type === 'success' ? 'bg-emerald-500 border-emerald-400 text-white' : 'bg-red-500 border-red-400 text-white'
    }`}>
      {type === 'success' ? <ICONS.CheckCircle2 size={18} /> : <ICONS.Shield size={18} />}
      <span className="text-xs font-bold">{message}</span>
    </div>
  );
};

const App: React.FC = () => {
  const [user, setUser] = useState<any>(null);
  const [polls, setPolls] = useState<any[]>([]);
  const [schedules, setSchedules] = useState<any[]>([]);
  const [announcements, setAnnouncements] = useState<any[]>([]);
  const [clubs, setClubs] = useState<any[]>([]);
  const [bookings, setBookings] = useState<any[]>([]);
  const [students, setStudents] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [toast, setToast] = useState<{ message: string, type: 'success' | 'error' } | null>(null);

  const refreshAll = useCallback(async (silent = false) => {
    if (!silent) setLoading(true);
    try {
      const [u, p, s, a, c, b, stu] = await Promise.all([
        Promise.resolve(db.get('user')),
        api.polls.getAll(),
        api.schedules.getAll(),
        api.announcements.getAll(),
        api.clubs.getAll(),
        api.bookings.getAll(),
        api.students.getAll()
      ]);
      setUser(u);
      setPolls(p);
      setSchedules(s);
      setAnnouncements(a);
      setClubs(c);
      setBookings(b);
      setStudents(stu);
    } catch (err: any) {
      logger.error("Failed to sync app state", err);
      setToast({ message: "Network sync failed", type: 'error' });
    } finally {
      if (!silent) setLoading(false);
    }
  }, []);

  useEffect(() => {
    db.init();
    refreshAll();
  }, [refreshAll]);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
  };

  if (loading && !user) return <GlobalLoader />;

  return (
    <Router>
      <div className="max-w-md mx-auto min-h-screen pb-24 relative shadow-2xl bg-white overflow-hidden flex flex-col">
        {loading && <GlobalLoader />}
        {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

        <Routes>
          <Route path="/" element={<HomeView announcements={announcements} schedules={schedules} onRefresh={() => refreshAll(true)} />} />
          <Route path="/schedule" element={<ScheduleView schedules={schedules} />} />
          <Route path="/clubs" element={<ClubsView clubs={clubs} />} />
          <Route path="/library" element={<LibraryView />} />
          <Route path="/profile" element={<ProfileView user={user} pollsCount={polls.filter(p => !p.hasVoted && p.status === 'open').length} />} />
          <Route path="/profile/edit" element={<EditProfileView user={user} onUpdate={(u) => { db.save('user', u); setUser(u); showToast("Profile updated"); }} />} />
          <Route path="/profile/help" element={<HelpSupportView />} />
          <Route path="/profile/hostel" element={<HostelBookingView user={user} onBook={async (b) => { 
            try { 
              await api.bookings.create(b); 
              showToast("Booking request sent");
              await refreshAll(true); 
            } catch (e: any) { showToast(e.message, 'error'); }
          }} />} />
          <Route path="/profile/polls" element={<PollsView polls={polls} onVote={async (id, option) => { 
            try {
              await api.polls.vote(id, option); 
              showToast("Vote recorded");
              await refreshAll(true);
            } catch (e: any) { showToast(e.message, 'error'); }
          }} />} />
          <Route path="/admin" element={<AdminDashboardView 
            polls={polls} 
            schedules={schedules}
            announcements={announcements}
            clubs={clubs}
            bookings={bookings}
            students={students}
            onUpdate={() => { refreshAll(true); showToast("Database updated"); }}
          />} />
        </Routes>
        <BottomNav />
      </div>
    </Router>
  );
};

export default App;

