                <div key={c.id} className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4 group">
                    <img src={c.image} className="w-14 h-14 rounded-2xl object-cover" />
                    <div className="flex-1 min-w-0">
                        <h4 className="font-bold text-sm text-slate-900 truncate">{c.name}</h4>
                        <div className="flex items-center gap-2 mt-0.5">
                            <span className="text-[9px] font-black text-[#0088CC] uppercase tracking-wider">{c.category}</span>
                            <span className="text-[9px] text-slate-300">•</span>
                            <span className="text-[9px] text-slate-400 font-bold uppercase">{c.members} MEMBERS</span>
                        </div>
                    </div>
                    <button onClick={() => handleDeleteClub(c.id)} className="text-slate-300 hover:text-red-500 p-2 active:scale-90 transition-transform">
                        <ICONS.LogOut size={16} className="rotate-90" />
                    </button>
                </div>
            ))}

            {activeTab === 'Library' && libraryFiles.map(f => (
                <div key={f.id} className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4">
                    <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400">
                        <ICONS.FileText size={22} />
                    </div>
                    <div className="flex-1 min-w-0">
                        <h4 className="font-bold text-sm text-slate-900 truncate">{f.name}</h4>
                        <div className="flex items-center gap-2 mt-0.5">
                            <span className="text-[9px] font-black text-[#0088CC] uppercase tracking-wider">{f.course}</span>
                            <span className="text-[9px] text-slate-300">•</span>
                            <span className="text-[9px] text-slate-400 font-bold uppercase">{f.type.replace('_', ' ')}</span>
                        </div>
                    </div>
                    <button onClick={() => handleDeleteFile(f.id)} className="text-slate-300 hover:text-red-500 p-2">
                        <ICONS.LogOut size={16} className="rotate-90" />
                    </button>
                </div>
            ))}

            {activeTab === 'Announcements' && announcements.map(ann => (
                <div key={ann.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm space-y-3">
                    <div className="flex justify-between items-start">
                        <div className="flex items-center gap-2">
                            <span className={`w-2 h-2 rounded-full ${
                                ann.category === 'URGENT' ? 'bg-red-500' :
                                ann.category === 'ACADEMIC' ? 'bg-emerald-500' : 'bg-blue-500'
                            }`}></span>
                            <span className={`text-[10px] font-black tracking-widest ${
                                ann.category === 'URGENT' ? 'text-red-500' :
                                ann.category === 'ACADEMIC' ? 'text-emerald-500' : 'text-blue-500'
                            }`}>{ann.category}</span>
                        </div>
                        <button 
                            onClick={() => handleDeleteAnnouncement(ann.id)}
                            className="text-slate-300 hover:text-red-500 transition-colors"
                        >
                            <ICONS.LogOut size={16} className="rotate-90" />
                        </button>
                    </div>
                    <div>
                        <h4 className="font-bold text-slate-900 text-sm mb-1">{ann.title}</h4>
                        <p className="text-slate-500 text-xs leading-relaxed line-clamp-2">{ann.message}</p>
                    </div>
                </div>
            ))}

            {activeTab === 'Hostel Management' && bookings.map(b => (
                <div key={b.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm space-y-4">
                    <div className="flex justify-between items-start">
                        <div className="flex items-center gap-3">
                            <div className={`w-10 h-10 rounded-2xl flex items-center justify-center ${b.status === 'booked' ? 'bg-emerald-50 text-emerald-500' : b.status === 'rejected' ? 'bg-red-50 text-red-500' : 'bg-amber-50 text-amber-500'}`}>
                                <ICONS.Building size={20} />
                            </div>
                            <div>
                                <h4 className="font-bold text-sm text-slate-900">{b.userName}</h4>
                                <p className="text-[10px] text-slate-400 font-bold uppercase">{b.hostelName} • Room {b.roomNumber}</p>
                            </div>
                        </div>
                        <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider ${
                            b.status === 'booked' ? 'bg-emerald-100 text-emerald-600' : 
                            b.status === 'pending' ? 'bg-amber-100 text-amber-600' : 'bg-red-100 text-red-600'
                        }`}>
                            {b.status.toUpperCase()}
                        </span>
                    </div>
                    {b.status === 'pending' && (
                        <div className="flex gap-2 pt-2 border-t border-slate-50">
                            <button onClick={() => handleUpdateBooking(b.id, 'booked')} className="flex-1 bg-emerald-500 text-white py-3 rounded-xl text-[10px] font-black uppercase tracking-widest">Accept</button>
                            <button onClick={() => handleUpdateBooking(b.id, 'rejected')} className="flex-1 bg-red-500 text-white py-3 rounded-xl text-[10px] font-black uppercase tracking-widest">Reject</button>
                        </div>
                    )}
                </div>
            ))}

            {activeTab === 'Polls' && polls.map(p => (
                <div key={p.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm space-y-4">
                    <div className="flex justify-between items-start">
                        <div className="flex-1 pr-4">
                            <h4 className="font-bold text-sm text-slate-900 leading-tight mb-1">{p.question}</h4>
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{p.totalVotes} votes • {p.status.toUpperCase()}</p>
                        </div>
                        <div className="flex gap-2">
                             <button onClick={() => handleTogglePollStatus(p.id)} className={`w-8 h-8 rounded-xl flex items-center justify-center ${p.status === 'open' ? 'bg-amber-50 text-amber-500' : 'bg-emerald-50 text-emerald-500'}`}>
                                <ICONS.Shield size={16} />
                             </button>
                             <button onClick={() => handleDeletePoll(p.id)} className="w-8 h-8 bg-red-50 text-red-500 rounded-xl flex items-center justify-center">
                                <ICONS.LogOut size={16} className="rotate-90" />
                             </button>
                        </div>
                    </div>
                </div>
            ))}
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-end animate-fade-in">
            <div className="w-full max-w-md mx-auto bg-white rounded-t-[3rem] p-8 space-y-6 max-h-[90vh] overflow-y-auto no-scrollbar shadow-2xl">
                <div className="flex justify-between items-center">
                    <h2 className="text-xl font-black text-slate-900 uppercase tracking-widest">Create {activeTab.slice(0, -1)}</h2>
                    <button onClick={() => setIsModalOpen(false)} className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-400">✕</button>
                </div>

                {activeTab === 'Clubs' && (
                    <div className="space-y-4">
                        <input type="text" placeholder="Club Name" className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newClub.name} onChange={e => setNewClub({...newClub, name: e.target.value})} />
                        <textarea placeholder="Description" className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm resize-none" rows={3} value={newClub.description} onChange={e => setNewClub({...newClub, description: e.target.value})} />
                        <button onClick={handleCreateClub} className="w-full bg-[#0088CC] text-white py-4 rounded-2xl font-black uppercase tracking-widest">Launch Club</button>
                    </div>
                )}

                {activeTab === 'Library' && (
                    <div className="space-y-4">
                        <input type="text" placeholder="File Name (e.g. Logic Notes.pdf)" className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newFile.name} onChange={e => setNewFile({...newFile, name: e.target.value})} />
                        <input type="text" placeholder="Course (e.g. CS101)" className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newFile.course} onChange={e => setNewFile({...newFile, course: e.target.value})} />
                        <select className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm appearance-none" value={newFile.type} onChange={e => setNewFile({...newFile, type: e.target.value as any})}>
                            <option value="slides">Slides</option>
                            <option value="past_questions">Past Questions</option>
                            <option value="books">Books</option>
                            <option value="notes">Notes</option>
                            <option value="other">Other</option>
                        </select>
                        <button onClick={handleCreateFile} className="w-full bg-[#0088CC] text-white py-4 rounded-2xl font-black uppercase tracking-widest">Upload Resource</button>
                    </div>
                )}

                {activeTab === 'Schedules' && (
                    <div className="space-y-4">
                        <input type="text" placeholder="Course ID" className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newSchedule.course_id} onChange={e => setNewSchedule({...newSchedule, course_id: e.target.value})} />
                        <input type="text" placeholder="Course Name" className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newSchedule.course_name} onChange={e => setNewSchedule({...newSchedule, course_name: e.target.value})} />
                        <button onClick={handleCreateSchedule} className="w-full bg-[#0088CC] text-white py-4 rounded-2xl font-black uppercase tracking-widest">Save Schedule</button>
                    </div>
                )}

                {activeTab === 'Announcements' && (
                    <div className="space-y-4">
                        <input type="text" placeholder="Title" className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newAnnouncement.title} onChange={e => setNewAnnouncement({...newAnnouncement, title: e.target.value})} />
                        <textarea placeholder="Message" className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm resize-none" rows={4} value={newAnnouncement.message} onChange={e => setNewAnnouncement({...newAnnouncement, message: e.target.value})} />
                        <button onClick={handleCreateAnnouncement} className="w-full bg-[#0088CC] text-white py-4 rounded-2xl font-black uppercase tracking-widest">Post</button>
                    </div>
                )}

                {activeTab === 'Polls' && (
                    <div className="space-y-4">
                        <input type="text" placeholder="Question" className="w-full bg-slate-50 border-none rounded-2xl p-4 text-sm" value={newPoll.question} onChange={e => setNewPoll({...newPoll, question: e.target.value})} />
                        <button onClick={handleCreatePoll} className="w-full bg-[#0088CC] text-white py-4 rounded-2xl font-black uppercase tracking-widest">Launch Poll</button>
                    </div>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboardView;

import React, { useState } from 'react';
import { ICONS } from '../constants';
import { FileType, LibraryFile } from '../types';

interface LibraryViewProps {
  libraryFiles: LibraryFile[];
}

const LibraryView: React.FC<LibraryViewProps> = ({ libraryFiles }) => {
  const [activeTab, setActiveTab] = useState<FileType | 'all'>('all');
  const [search, setSearch] = useState('');

  const tabs: { label: string; value: FileType | 'all'; Icon: any }[] = [
    { label: 'All Files', value: 'all', Icon: ICONS.FileText },
    { label: 'Slides', value: 'slides', Icon: ICONS.Info },
    { label: 'Past Questions', value: 'past_questions', Icon: ICONS.HelpCircle },
    { label: 'Books', value: 'books', Icon: ICONS.Library },
  ];

  const filteredFiles = libraryFiles.filter(f => {
    const matchesTab = activeTab === 'all' || f.type === activeTab;
    const matchesSearch = f.name.toLowerCase().includes(search.toLowerCase()) || f.course.toLowerCase().includes(search.toLowerCase());
    return matchesTab && matchesSearch;
  });

  return (
    <div className="flex-1 p-6 animate-fade-in overflow-y-auto no-scrollbar">
      <div className="mb-6">
        <p className="text-slate-400 text-sm font-medium">Campus</p>
        <h1 className="text-2xl font-bold text-slate-900">Library</h1>
      </div>

      <div className="relative mb-8">
        <ICONS.Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
        <input
          type="text"
          placeholder="Search files, courses..."
          className="w-full bg-white border border-slate-100 rounded-2xl py-3.5 pl-12 pr-4 text-sm focus:outline-none focus:ring-2 focus:ring-blue-100 transition-all shadow-sm"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="flex gap-2 overflow-x-auto no-scrollbar mb-8 -mx-6 px-6">
        {tabs.map((tab) => (
          <button
            key={tab.value}
            onClick={() => setActiveTab(tab.value)}
            className={`px-5 py-2.5 rounded-full text-xs font-bold whitespace-nowrap flex items-center gap-2 transition-all ${
              activeTab === tab.value
                ? 'bg-[#0088CC] text-white shadow-lg shadow-blue-100'
                : 'bg-white text-slate-400 border border-slate-100'
            }`}
          >
            <tab.Icon size={14} />
            {tab.label}
          </button>
        ))}
      </div>

      <div className="mb-6">
          <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">{filteredFiles.length} FILES AVAILABLE</span>
      </div>

      <div className="space-y-4 pb-4">
        {filteredFiles.map((file) => (
          <div key={file.id} className="bg-white rounded-3xl p-4 shadow-sm border border-slate-100 flex items-center gap-4 group active:scale-[0.98] transition-transform">
            <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center group-hover:bg-blue-50 transition-colors">
                <ICONS.FileText className="text-slate-400 group-hover:text-[#0088CC]" size={22} />
            </div>
            <div className="flex-1 min-w-0">
              <h3 className="font-bold text-slate-900 text-sm truncate mb-1">{file.name}</h3>
              <div className="flex items-center gap-3 text-[10px] font-bold text-slate-400">
                <span className="bg-blue-50 text-[#0088CC] px-2 py-0.5 rounded uppercase">{file.course}</span>
                <span>{file.size}</span>
                <span>{file.date}</span>
              </div>
              <div className="flex items-center gap-1 mt-1">
                  <ICONS.Download size={10} className="text-slate-300" />
                  <span className="text-[10px] font-medium text-slate-300">{file.downloads} downloads</span>
              </div>
            </div>
            <button className="w-10 h-10 bg-blue-50 rounded-full flex items-center justify-center text-[#0088CC] active:scale-90 transition-transform">
              <ICONS.Download size={18} />
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default LibraryView;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { Poll, ClassSchedule, Announcement, Club, HostelBooking, User, LibraryFile, BookingStatus, TargetType } from '../types';
import { api } from '../services/api';

interface AdminDashboardProps {
  polls: Poll[];
  schedules: ClassSchedule[];
  announcements: Announcement[];
  clubs: Club[];
  bookings: HostelBooking[];
  students: User[];
  libraryFiles: LibraryFile[];
  onUpdate: () => void;
}

const AdminDashboardView: React.FC<AdminDashboardProps> = ({ 
  polls, schedules, announcements, clubs, bookings, students, libraryFiles, onUpdate
}) => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('Schedules');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  // Form states
  const initialClub = { name: '', description: '', category: 'Technology', whatsapp: '', image: 'https://picsum.photos/400/200?random=' + Math.floor(Math.random() * 100) };
  const initialSchedule = { course_id: '', course_name: '', instructor_name: '', day_of_week: 'Monday', start_time: '08:00', end_time: '10:00', location: '', semester: '1st SEM 2024/25' };
  const initialPoll = { question: '', options: ['', ''], endDate: new Date(Date.now() + 604800000).toISOString().split('T')[0] };
  const initialAnnouncement = { title: '', message: '', category: 'GENERAL' as Announcement['category'], target_type: 'all' as TargetType };
  const initialFile = { name: '', type: 'slides' as LibraryFile['type'], course: '', size: '1.2 MB' };

  const [newClub, setNewClub] = useState(initialClub);
  const [newSchedule, setNewSchedule] = useState(initialSchedule);
  const [newPoll, setNewPoll] = useState(initialPoll);
  const [newAnnouncement, setNewAnnouncement] = useState(initialAnnouncement);
  const [newFile, setNewFile] = useState(initialFile);

  // Reset forms on tab change or modal close
  useEffect(() => {
    if (!isModalOpen) {
      setNewClub(initialClub);
      setNewSchedule(initialSchedule);
      setNewPoll(initialPoll);
      setNewAnnouncement(initialAnnouncement);
      setNewFile(initialFile);
    }
  }, [isModalOpen, activeTab]);

  const wrapAction = async (promise: Promise<any>) => {
    setIsProcessing(true);
    try {
      await promise;
      onUpdate();
      setIsModalOpen(false);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateClub = () => wrapAction(api.clubs.create(newClub));
  const handleCreateSchedule = () => wrapAction(api.schedules.create(newSchedule));
  const handleCreatePoll = () => wrapAction(api.polls.create(newPoll));
  const handleCreateAnnouncement = () => wrapAction(api.announcements.create(newAnnouncement));
  const handleCreateFile = () => wrapAction(api.library.create(newFile));

  const handleDeleteAnnouncement = (id: string) => wrapAction(api.announcements.delete(id));
  const handleDeleteSchedule = (id: string) => wrapAction(api.schedules.delete(id));
  const handleDeletePoll = (id: string) => wrapAction(api.polls.delete(id));
  const handleDeleteClub = (id: string) => wrapAction(api.clubs.delete(id));
  const handleDeleteFile = (id: string) => wrapAction(api.library.delete(id));

  const handleTogglePollStatus = (id: string) => wrapAction(api.polls.toggleStatus(id));
  const handleUpdateBooking = (id: string, status: BookingStatus) => wrapAction(api.bookings.updateStatus(id, status));

  // Validation Logic
  const isClubValid = newClub.name.trim() !== '' && newClub.description.trim() !== '';
  const isFileValid = newFile.name.trim() !== '' && newFile.course.trim() !== '';
  const isScheduleValid = newSchedule.course_id.trim() !== '' && newSchedule.course_name.trim() !== '' && newSchedule.location.trim() !== '';
  const isAnnouncementValid = newAnnouncement.title.trim() !== '' && newAnnouncement.message.trim() !== '';
  const isPollValid = newPoll.question.trim() !== '' && newPoll.options.every(o => o.trim() !== '');

  const tabs = ['Schedules', 'Polls', 'Announcements', 'Clubs', 'Hostel Management', 'Library', 'Students'];

  return (
    <div className="flex-1 bg-slate-50 flex flex-col animate-fade-in relative h-full">
      {isProcessing && (
        <div className="absolute inset-0 bg-white/50 backdrop-blur-[1px] z-50 flex items-center justify-center">
          <div className="w-8 h-8 border-2 border-[#0088CC] border-t-transparent rounded-full animate-spin"></div>
        </div>
      )}

      <div className="p-6 bg-white flex items-center justify-between shadow-sm">
        <button onClick={() => navigate('/profile')} className="p-2 -ml-2 hover:bg-slate-50 rounded-full transition-colors">
          <ICONS.ChevronRight size={24} className="rotate-180 text-slate-600" />
        </button>
        <h1 className="font-black text-slate-900 uppercase tracking-widest text-xs">Campus Admin</h1>
        <div className="w-10"></div>
      </div>

      <div className="p-6 space-y-6 overflow-y-auto no-scrollbar flex-1 pb-10">
        <div className="flex gap-2 overflow-x-auto no-scrollbar py-2 -mx-6 px-6 bg-white border-b border-slate-100">
            {tabs.map(t => (
                <button 
                    key={t}
                    onClick={() => setActiveTab(t)}
                    className={`py-2 px-4 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all whitespace-nowrap ${
                        activeTab === t ? 'bg-[#0088CC] text-white shadow-lg' : 'text-slate-400 bg-slate-50'
                    }`}
                >
                    {t}
                </button>
            ))}
        </div>

        <div className="flex justify-between items-center">
            <h3 className="text-sm font-black text-slate-900 uppercase tracking-[0.2em]">{activeTab}</h3>
            {['Schedules', 'Polls', 'Announcements', 'Clubs', 'Library'].includes(activeTab) && (
                <button onClick={() => setIsModalOpen(true)} className="bg-[#0088CC] text-white w-10 h-10 rounded-2xl flex items-center justify-center shadow-lg active:scale-90 transition-transform">
                    <span className="text-2xl font-light">+</span>
                </button>
            )}
        </div>

        <div className="space-y-4">
            {activeTab === 'Schedules' && schedules.map(s => (
                <div key={s.id} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm space-y-3">
                    <div className="flex justify-between items-start">
                        <div className="flex items-center gap-3">
                            <div className="w-10 h-10 bg-blue-50 text-[#0088CC] rounded-xl flex items-center justify-center">
                                <ICONS.Calendar size={20} />
                            </div>
                            <div>
                                <h4 className="font-bold text-sm text-slate-900 leading-tight">{s.course_id}: {s.course_name}</h4>
                                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{s.instructor_name}</p>
                            </div>
                        </div>
                        <button onClick={() => handleDeleteSchedule(s.id)} className="text-slate-300 hover:text-red-500 transition-colors p-1">
                            <ICONS.LogOut size={16} className="rotate-90" />
                        </button>
                    </div>
                </div>
            ))}

            {activeTab === 'Clubs' && clubs.map(c => (
                <div key={c.id} className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4 group">
                    <img src={c.image} className="w-14 h-14 rounded-2xl object-cover" />
                    <div className="flex-1 min-w-0">
                        <h4 className="font-bold text-sm text-slate-900 truncate">{c.name}</h4>
                        <div className="flex items-center gap-2 mt-0.5">
                            <span className="text-[9px] font-black text-[#0088CC] uppercase tracking-wider">{c.category}</span>
                            <span className="text-[9px] text-slate-300">•</span>
                            <span className="text-[9px] text-slate-400 font-bold uppercase">{c.members} MEMBERS</span>
                        </div>
                    </div>
                    <button onClick={() => handleDeleteClub(c.id)} className="text-slate-300 hover:text-red-500 p-2 active:scale-90 transition-transform">
                        <ICONS.LogOut size={16} className="rotate-90" />
                    </button>
                </div>
            ))}

            {activeTab === 'Library' && libraryFiles.map(f => (
                <div key={f.id} className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-4">
                    <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400">
                        <ICONS.FileText size={22} />
                    </div>
                    <div className="flex-1 min-w-0">
                        <h4 className="font-bold text-sm text-slate-900 truncate">{f.name}</h4>
                        <div className="flex items-center gap-2 mt-0.5">
                            <span className="text-[9px] font-black text-[#0088CC] uppercase tracking-wider">{f.course}</span>
                            <span className="text-[9px] text-slate-300">•</span>
                            <span className="text-[9px] text-slate-400 font-bold uppercase">{f.type.replace('_', ' ')}</span>
                        </div>
                    </div>
                    <button onClick={() => handleDeleteFile(f.id)} className="text-slate-300 hover:text-red-500 p-2">
                        <ICONS.LogOut size={16} className="rotate-90" />
                    </button>
                </div>
            ))}

            {activeTab === 'Announcements' && announcements.map(ann => (
